import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext'; 
import { useAuth } from '../../contexts/AuthContext';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import { CloudArrowUpIcon, DocumentArrowDownIcon, PhotoIcon, SparklesIcon, TableCellsIcon } from '../Icons';

// Sub-componentes
import { ImageRenderer } from './preprocessor/ImageRenderer';
import { SpreadsheetRenderer } from './preprocessor/SpreadsheetRenderer';
import { SimulatedResultsTable } from './preprocessor/SimulatedResultsTable';
import { MappingControls } from './preprocessor/MappingControls';
import { TeachingBanner } from './preprocessor/TeachingBanner';
import { PreprocessorHeader } from './preprocessor/PreprocessorHeader';

// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords } = useContext(AppContext);

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile: File } | null>(null);
    const activeFile = initialFile || uploadedFile || null;

    // Identifica se é uma imagem ou um arquivo de dados estruturados
    const isImage = useMemo(() => /\.(jpg|jpeg|png|webp)$/i.test(activeFile?.fileName || ''), [activeFile]);
    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);

    const cleaningKeywords = useMemo(() => [...effectiveIgnoreKeywords, ...contributionKeywords], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading, isAiProcessing, 
        activeMapping, setActiveMapping, detectedFingerprint 
    } = useFileProcessing({ activeFile, initialModel, isImage, isPdf });

    const {
        processedTransactions, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ gridData, activeMapping, cleaningKeywords });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ gridData, setGridData, setActiveMapping, showToast });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.slice(0, 50).map(row => row.join(';')).join('\n');
            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: detectedFingerprint, 
                mapping: activeMapping, 
                parsingRules: { 
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [], 
                    rowFilters: [] 
                }, 
                snippet: finalSnippet, 
                lastUsedAt: new Date().toISOString(), 
                status: approvalStatus, 
                approvedBy: approvalStatus === 'approved' ? user.id : undefined, 
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined 
            };
            const saved = await modelService.saveModel(modelData);
            showToast(approvalStatus === 'approved' ? "Modelo aprovado!" : "Layout salvo como rascunho.", "success");
            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions.filter(t => t.isValid));
            } else {
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão estrutural.", "error"); 
        } finally { 
            setIsSavingModel(false); 
        }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, processedTransactions, onSuccess, onClose, showToast]);

    const handleInternalUpload = (content: string, fileName: string, rawFile: File) => {
        setUploadedFile({ content, fileName, rawFile });
    };

    const canApprove = processedTransactions.length > 0 && mode !== 'test';

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/95 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Treinamento de Layout'} 
                    canApprove={canApprove} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    {/* COLUNA ESQUERDA: ARQUIVO ORIGINAL (VISUALIZAÇÃO DA ESTRUTURA) */}
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-[#0B1120] relative">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex gap-3 items-center z-20 shrink-0 min-h-[56px]">
                            {activeFile ? (
                                <MappingControls 
                                    mapping={activeMapping} 
                                    setMapping={setActiveMapping} 
                                    columnCount={gridData[0]?.length || 0} 
                                    onSimulate={runSimulation}
                                    gridData={gridData}
                                />
                            ) : (
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-2 flex items-center gap-2">
                                    <TableCellsIcon className="w-3 h-3" /> Selecione um arquivo para começar o treinamento...
                                </div>
                            )}
                        </div>

                        <div className="flex-1 relative overflow-hidden">
                            {isGridLoading || isAiProcessing ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-900 z-30">
                                     <div className="animate-spin rounded-full h-10 w-10 border-4 border-indigo-500 border-t-transparent mb-4"></div>
                                     <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                         {isAiProcessing ? 'Interpretando visual da imagem...' : 'Lendo estrutura real do arquivo...'}
                                     </p>
                                </div>
                            ) : !activeFile ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                                    <div className="w-20 h-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-3xl flex items-center justify-center mb-6 text-indigo-500 shadow-inner">
                                        <TableCellsIcon className="w-10 h-10" />
                                    </div>
                                    <h4 className="text-xl font-black text-slate-800 dark:text-white mb-2">Treinar Novo Modelo</h4>
                                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mb-8 leading-relaxed">
                                        Suba um arquivo original (CSV, Excel, PDF) ou uma foto de extrato para ensinar o padrão estrutural ao sistema.
                                    </p>
                                    <FileUploader 
                                        id="internal-preprocessor-upload"
                                        title="Selecionar Arquivo de Exemplo"
                                        onFileUpload={handleInternalUpload}
                                        isUploaded={false}
                                        uploadedFileName={null}
                                        useLocalLoadingOnly={true} 
                                    />
                                </div>
                            ) : (
                                isImage ? <ImageRenderer file={activeFile.rawFile!} /> : <SpreadsheetRenderer data={gridData} detectedMapping={activeMapping} />
                            )}
                        </div>
                    </section>

                    {/* COLUNA DIREITA: SIMULAÇÃO DO MODELO */}
                    <section className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] border-l border-slate-200 dark:border-slate-800">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 flex items-center justify-between shrink-0">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                                <SparklesIcon className="w-4 h-4 text-indigo-500" /> Simulação de Processamento
                            </h4>
                            <span className="text-[9px] font-bold text-slate-400 bg-white dark:bg-slate-800 px-2 py-0.5 rounded-full border border-slate-200 dark:border-slate-700">
                                {processedTransactions.length} linhas lidas
                            </span>
                        </div>

                        <TeachingBanner isVisible={!!learnedPatternSource} isProcessing={isInferringMapping} onApply={handleApplyCorrectionPattern} />

                        <div className="flex-1 overflow-auto custom-scrollbar">
                            {!activeFile ? (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center opacity-40">
                                    <DocumentArrowDownIcon className="w-12 h-12 mb-3" />
                                    <p className="text-xs font-bold uppercase tracking-widest">Aguardando arquivo para simulação</p>
                                </div>
                            ) : (
                                <SimulatedResultsTable 
                                    transactions={processedTransactions} 
                                    activeMapping={!!activeMapping} 
                                    isTestMode={mode === 'test'} 
                                    editingRowIndex={editingRowIndex} 
                                    editingRowData={editingRowData} 
                                    onStartEdit={startEdit} 
                                    onSaveRow={() => saveRow((original, corrected) => setLearnedPatternSource({ originalRaw: original, corrected }))} 
                                    onCancelEdit={cancelEdit} 
                                    onUpdateEditingData={setEditingRowData} 
                                />
                            )}
                        </div>
                    </section>
                </div>

                {showNameModal && (
                    <div className="fixed inset-0 z-[10000] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm border border-white/10 animate-scale-in text-center">
                            <h3 className="text-xl font-black text-slate-800 dark:text-white mb-2">Nomear Padrão Estrutural</h3>
                            <p className="text-xs text-slate-500 mb-6 font-medium">Este nome será usado para identificar o layout no processamento automático.</p>
                            <input type="text" autoFocus value={modelName} onChange={e => setModelName(e.target.value)} className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-white mb-6 outline-none font-bold" placeholder="Ex: Extrato Santander - Mensal" />
                            <div className="flex gap-3">
                                <button onClick={() => setShowNameModal(false)} className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl font-bold uppercase text-[10px] text-slate-600 dark:text-slate-400">Cancelar</button>
                                <button onClick={() => { setShowNameModal(false); handlePersistModel(pendingAction, modelName); }} disabled={isSavingModel || !modelName.trim()} className="flex-1 py-3 bg-indigo-600 text-white rounded-2xl font-bold uppercase text-[10px] shadow-lg shadow-indigo-500/30">
                                    {isSavingModel ? 'Salvando...' : 'Aprovar e Salvar'}
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
};

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { generateFingerprint } from '../services/processingService';
import { extractDataFromVisual } from '../services/geminiService';
import { FileModel } from '../types';
import { useUI } from '../contexts/UIContext';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isImage: boolean;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isImage, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);
    const { showToast } = useUI();

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                // FLUXO A: IMAGENS (Treinamento Visual)
                if (isImage && activeFile.rawFile) {
                    setIsAiProcessing(true);
                    const aiResult = await extractDataFromVisual(activeFile.rawFile);
                    try {
                        const parsed = JSON.parse(aiResult);
                        if (parsed?.rows && Array.isArray(parsed.rows)) {
                            loadedRows = parsed.rows.map((r: any) => [
                                String(r.date || ''),
                                String(r.description || ''),
                                r.amount !== undefined ? String(r.amount) : '',
                                String(r.type || '')
                            ]);

                            setActiveMapping({
                                dateColumnIndex: 0,
                                descriptionColumnIndex: 1,
                                amountColumnIndex: 2,
                                typeColumnIndex: 3,
                                skipRowsStart: 0,
                                skipRowsEnd: 0,
                                decimalSeparator: '.',
                                thousandsSeparator: ''
                            });
                        }
                    } catch (e) {
                        showToast("A IA não conseguiu estruturar os dados da foto.", "error");
                    }
                } 
                // FLUXO B: EXCEL (Treinamento Estrutural Real)
                else if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } 
                // FLUXO C: CSV / TEXTO (Treinamento Estrutural Real)
                else {
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                        if (lines.length > 0) {
                            // Detecta delimitador dinamicamente para gerar a grid
                            const firstLine = lines[0];
                            const delimiter = firstLine.includes(';') ? ';' : (firstLine.includes('\t') ? '\t' : ',');
                            loadedRows = lines.map((l: string) => l.split(delimiter));
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);

                    // Geração do Fingerprint REAL do arquivo (O DNA para match automático)
                    // Importante: Usamos o conteúdo bruto original se disponível, senão usamos a grid sintetizada
                    const sampleContent = activeFile.content || loadedRows.slice(0, 20).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContent);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!activeMapping) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no processamento do laboratório:", err);
                showToast("Erro ao ler estrutura do arquivo.", "error");
            } finally {
                setIsGridLoading(false);
                setIsAiProcessing(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, isImage, initialModel, showToast]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import { CanonicalDocumentNormalizer } from './CanonicalDocumentNormalizer';

/**
 * SERVIÇO DE DOMÍNIO: FINGERPRINTER (V2 - ULTRA ROBUSTO)
 * --------------------------------------------------------------------------
 * Responsável por gerar a identidade estrutural (DNA) de qualquer conteúdo tabular.
 * Focado em estabilidade: Pequenas mudanças de espaços não alteram o DNA.
 */

export interface StructuralFingerprint {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;
    canonicalSignature?: string;
    structuralPattern?: string;
}

export const Fingerprinter = {
    /**
     * Detecta o delimitador de forma estatística.
     */
    detectDelimiter: (line: string): string => {
        const candidates = [';', ',', '\t', '|'];
        const counts = candidates.map(char => ({ 
            char, 
            count: (line || '').split(char).length - 1 
        }));
        counts.sort((a, b) => b.count - a.count);
        return counts[0].count > 0 ? counts[0].char : ';';
    },

    /**
     * Gera o DNA estrutural para reconhecimento independente de formato.
     */
    generate: (content: string): StructuralFingerprint | null => {
        if (!content || typeof content !== 'string') return null;

        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return null;

        const firstLine = lines[0];
        const delimiter = Fingerprinter.detectDelimiter(firstLine);
        const cells = firstLine.split(delimiter);

        // 1. HASH DE CABEÇALHO NORMALIZADO (Imune a espaços e caracteres invisíveis)
        const cleanHeader = firstLine
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '') 
            .replace(/[^A-Z0-9]/gi, '')      
            .toUpperCase();

        const headerHash = cleanHeader.split('').reduce((a, b) => { 
            a = ((a << 5) - a) + b.charCodeAt(0); 
            return a & a; 
        }, 0).toString(36);

        // 2. ASSINATURA CANÔNICA E PADRÃO ESTRUTURAL (Core v3)
        // Isso é o que garante que CSV aprende com CSV e bate na execução.
        const canonicalSignature = CanonicalDocumentNormalizer.generateSignature(lines);
        const structuralPattern = CanonicalDocumentNormalizer.generateStructuralPattern(lines);

        // 3. TOPOLOGIA DE DADOS (DNA de Tipos)
        // Analisa as linhas de dados reais, ignorando o cabeçalho se necessário.
        const dataRows = lines.slice(0, 15);
        const representativeRow = dataRows.find(r => {
            const c = r.split(delimiter);
            // Procura linha que tenha pelo menos uma data ou valor numérico
            return c.length >= 2 && (r.match(/\d[/-]\d/) || r.match(/\d,\d/));
        }) || firstLine;

        const topologyString = representativeRow.split(delimiter).map(c => {
            const val = c.trim().replace(/[R$\s]/g, '').replace(',', '.');
            if (/^\d{1,4}[/-]\d{1,2}[/-]\d{1,4}$/.test(val) || /^\d{1,2}[/-]\d{1,2}$/.test(val)) return 'D';
            if (!isNaN(parseFloat(val)) && /\d/.test(val)) return 'N';
            if (val.length === 0) return 'E';
            return 'S';
        }).join('');

        return { 
            columnCount: cells.length, 
            delimiter, 
            headerHash, 
            dataTopology: topologyString,
            canonicalSignature,
            structuralPattern
        };
    }
};

import { NameResolver } from './NameResolver';

/**
 * NORMALIZADOR CANÔNICO DE DOCUMENTOS (Core v3)
 * Responsável por transformar conteúdo bruto em uma representação estrutural unificada.
 */
export class CanonicalDocumentNormalizer {

    static generateSignature(lines: string[]): string {
        if (!lines || lines.length === 0) return '';
        const canonicalHeader = this.normalizeLine(lines[0], true);
        const dataSample = lines.slice(1, 11);
        const topologySignature = dataSample.map(line => this.getTopologyPattern(line)).join('|');
        const rawSignature = `${canonicalHeader}||${topologySignature}`;
        return this.simpleHash(rawSignature);
    }

    static generateStructuralPattern(lines: string[]): string {
        if (lines.length < 2) return 'UNKNOWN';
        const sampleRows = lines.slice(0, 30); 
        const patterns: string[] = [];

        for (const line of sampleRows) {
            const delimiter = line.includes(';') ? ';' : (line.includes('\t') ? '\t' : ',');
            const cells = line.split(delimiter);
            const rowEntities: string[] = [];

            for (const cell of cells) {
                const type = this.getCellType(cell.trim());
                if (type === 'XX') continue; 
                rowEntities.push(type);
            }

            // Uma linha de dados válida deve ter pelo menos uma data ou um valor.
            if (rowEntities.includes('DT') || rowEntities.includes('NM')) {
                patterns.push(rowEntities.join('-'));
            }
        }

        if (patterns.length === 0) return 'UNKNOWN';
        return this.getMode(patterns);
    }

    private static getCellType(token: string): string {
        if (!token) return 'XX';
        if (/\b\d{1,2}[/-]\d{1,2}([/-]\d{2,4})?/.test(token) || /\d{4}-\d{2}-\d{2}/.test(token)) return 'DT';
        const cleanNum = token.replace(/[R$\s]/g, '').replace(',', '.');
        if (!isNaN(parseFloat(cleanNum)) && /\d/.test(cleanNum)) return 'NM';
        if (token.length < 2 && !/\d/.test(token)) return 'XX';
        return 'ST';
    }

    private static getMode(array: string[]): string {
        if (array.length === 0) return 'UNKNOWN';
        const modeMap: Record<string, number> = {};
        let maxEl = array[0], maxCount = 1;
        for (const el of array) {
            modeMap[el] = (modeMap[el] || 0) + 1;
            if (modeMap[el] > maxCount) {
                maxEl = el;
                maxCount = modeMap[el];
            }
        }
        return maxEl;
    }

    static normalizeLine(line: string, isHeader: boolean = false): string {
        if (!line) return '';
        let normalized = line.toUpperCase();
        normalized = NameResolver.normalize(normalized);
        normalized = normalized.replace(/[;,\t|]/g, ' ');
        normalized = normalized.replace(/[^A-Z0-9\s]/g, '');
        normalized = normalized.replace(/\s+/g, ' ').trim();
        if (isHeader) return normalized;
        return normalized.replace(/\d+/g, '#NUM');
    }

    private static getTopologyPattern(line: string): string {
        const delimiter = line.includes(';') ? ';' : (line.includes('\t') ? '\t' : ',');
        const cells = line.split(delimiter);
        return cells.map(c => this.getCellType(c.trim())).join('.');
    }

    private static simpleHash(str: string): string {
        let hash = 5381;
        for (let i = 0; i < str.length; i++) {
            hash = ((hash << 5) + hash) + str.charCodeAt(i);
        }
        return (hash >>> 0).toString(36).toUpperCase();
    }
}

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || {
            dateColumnIndex: -1,
            descriptionColumnIndex: -1,
            amountColumnIndex: -1,
            skipRowsStart: 0
        };

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

        const newTransactions: SafeTransaction[] = [];
        // Utiliza a inteligência de descoberta de ano do Core Engine
        const yearAnchor = DateResolver.discoverAnchorYear(gridData);

        const sampleData = gridData.slice(0, 50);

        sampleData.forEach((cols, index) => {
            if (!RowValidator.isPotentialRow(cols)) return;

            const isSkipped = index < (skipRowsStart || 0);

            // Se não houver mapeamento definido, exibe visualização bruta
            if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                newTransactions.push({ 
                    id: `sim-raw-${index}`, 
                    date: "---", 
                    description: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    rawDescription: cols.join('|'), 
                    amount: 0, 
                    originalAmount: "0.00", 
                    cleanedDescription: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    contributionType: "BRUTO", 
                    sourceIndex: index, 
                    isValid: false, 
                    status: 'pending' 
                });
                return;
            }

            const rawDate = cols[dateColumnIndex] || '';
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex] || '';
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? cols[typeColumnIndex] : '';

            // EXECUÇÃO DOS RESOLVERS REAIS (Garante que o que você vê no lab é o que acontece no motor)
            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);
            const cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
            const finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);

            // Validação rigorosa conforme RowValidator do motor de execução
            const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;

            const status: SafeTransaction['status'] = isSkipped ? 'ignored' : (isValid ? 'valid' : 'error');

            newTransactions.push({ 
                id: `sim-${index}`, 
                date: (isValid || status === 'valid') ? isoDate : (rawDate || "---"), 
                description: rawDesc || "---", 
                rawDescription: rawDesc || "---", 
                amount, 
                originalAmount: String(rawAmount), 
                cleanedDescription: cleanedDesc, 
                contributionType: finalType, 
                sourceIndex: index, 
                isValid, 
                status 
            });
        });

        setProcessedTransactions(newTransactions);
    }, [gridData, activeMapping, cleaningKeywords]);

    useEffect(() => {
        const dataKey = `${gridData.length}-${gridData[0]?.length || 0}`;
        const mappingKey = JSON.stringify(activeMapping);

        if (dataKey !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataKey;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = { ...editingRowData, status: 'edited', isValid: true };
                return n;
            });

            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], editingRowData);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v10';

const getConsolidatedLocalModels = async (): Promise<FileModel[]> => {
    try {
        const currentModels = await get(PERSISTENT_STORAGE_KEY);
        return Array.isArray(currentModels) ? currentModels : [];
    } catch (e) { 
        return []; 
    }
};

const mapDbRowToModel = (row: any): FileModel => ({
    id: row.id,
    name: row.name,
    user_id: row.user_id,
    version: row.version || 1,
    lineage_id: row.lineage_id || row.id,
    is_active: row.is_active,
    status: row.status || 'draft',
    fingerprint: typeof row.fingerprint === 'string' ? JSON.parse(row.fingerprint) : row.fingerprint,
    mapping: typeof row.mapping === 'string' ? JSON.parse(row.mapping) : row.mapping,
    parsingRules: row.parsing_rules ? (typeof row.parsing_rules === 'string' ? JSON.parse(row.parsing_rules) : row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
    snippet: row.snippet,
    createdAt: row.created_at || new Date().toISOString(),
    lastUsedAt: row.last_used_at
});

export const modelService = {
    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        const localId = `local-${Date.now()}`;
        const newModel: FileModel = {
            ...model,
            id: localId,
            createdAt: new Date().toISOString()
        };

        try {
            // Tenta desativar versões antigas remotamente
            await supabase.from('file_models').update({ is_active: false }).eq('lineage_id', model.lineage_id);

            // PAYLOAD: Persistência completa do DNA estrutural
            const dbPayload = {
                name: model.name,
                user_id: model.user_id,
                version: model.version,
                lineage_id: model.lineage_id,
                is_active: true,
                status: model.status || 'draft',
                fingerprint: model.fingerprint, // Aqui já contém canonicalSignature e structuralPattern
                mapping: model.mapping,
                snippet: model.snippet || null
            };

            const { data, error } = await supabase
                .from('file_models')
                .insert([dbPayload])
                .select()
                .single();

            if (error) throw error;
            return mapDbRowToModel(data);

        } catch (error: any) {
            Logger.warn("Salvando modelo no storage local devido a erro na nuvem ou falta de conexão.", error);

            const currentLocals = await getConsolidatedLocalModels();
            const updatedLocals = [newModel, ...currentLocals.filter(m => m.lineage_id !== model.lineage_id)];
            await set(PERSISTENT_STORAGE_KEY, updatedLocals);

            return newModel;
        }
    },

    getUserModels: async (userId: string): Promise<FileModel[]> => {
        let remoteModels: FileModel[] = [];
        try {
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('user_id', userId)
                .eq('is_active', true);

            if (!error && data) {
                remoteModels = data.map(mapDbRowToModel);
            }
        } catch (e) {
            console.error("Falha ao ler modelos remotos", e);
        }

        const localModels = await getConsolidatedLocalModels();
        const userLocals = localModels.filter(m => m.user_id === userId);

        const uniqueModels = new Map<string, FileModel>();
        [...remoteModels, ...userLocals].forEach(m => {
            const existing = uniqueModels.get(m.lineage_id);
            if (!existing || new Date(m.createdAt) > new Date(existing.createdAt)) {
                uniqueModels.set(m.lineage_id, m);
            }
        });

        return Array.from(uniqueModels.values());
    },

    getAllModelsAdmin: async (): Promise<(FileModel & { user_email?: string })[]> => {
        let remote: any[] = [];
        try {
            const { data } = await supabase.from('file_models').select('*').eq('is_active', true);
            remote = (data || []).map(mapDbRowToModel);
        } catch (e) {}

        const local = await getConsolidatedLocalModels();
        return [...remote, ...local];
    },

    deleteModel: async (id: string) => {
        if (id.startsWith('local-')) {
            const current = await getConsolidatedLocalModels();
            await set(PERSISTENT_STORAGE_KEY, current.filter(m => m.id !== id));
            return true;
        }
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        return !error;
    },

    updateModelName: async (id: string, name: string) => {
        if (id.startsWith('local-')) {
            const current = await getConsolidatedLocalModels();
            await set(PERSISTENT_STORAGE_KEY, current.map(m => m.id === id ? {...m, name} : m));
            return true;
        }
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        return !error;
    }
};

import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
