// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords } = useContext(AppContext);

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile: File } | null>(null);
    const activeFile = initialFile || uploadedFile || null;

    // Identificadores de formato
    const isImage = useMemo(() => /\.(jpg|jpeg|png|webp)$/i.test(activeFile?.fileName || ''), [activeFile]);
    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);
    const isSpreadsheet = useMemo(() => /\.(xlsx|xls|csv)$/i.test(activeFile?.fileName || ''), [activeFile]);

    const cleaningKeywords = useMemo(() => [...effectiveIgnoreKeywords, ...contributionKeywords], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading, isAiProcessing, 
        activeMapping, setActiveMapping, detectedFingerprint 
    } = useFileProcessing({ activeFile, initialModel, isImage, isPdf });

    const {
        processedTransactions, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ gridData, activeMapping, cleaningKeywords });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ gridData, setGridData, setActiveMapping, showToast });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.slice(0, 50).map(row => row.join(';')).join('\n');
            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: detectedFingerprint, 
                mapping: activeMapping, 
                parsingRules: { 
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [], 
                    rowFilters: [] 
                }, 
                snippet: finalSnippet, 
                lastUsedAt: new Date().toISOString(), 
                status: approvalStatus, 
                approvedBy: approvalStatus === 'approved' ? user.id : undefined, 
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined 
            };
            const saved = await modelService.saveModel(modelData);
            showToast(approvalStatus === 'approved' ? "Modelo aprovado!" : "Layout salvo como rascunho.", "success");
            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions.filter(t => t.isValid));
            } else {
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão estrutural.", "error"); 
        } finally { 
            setIsSavingModel(false); 
        }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, processedTransactions, onSuccess, onClose, showToast]);

    const handleInternalUpload = (content: string, fileName: string, rawFile: File) => {
        setUploadedFile({ content, fileName, rawFile });
    };

    const canApprove = processedTransactions.length > 0 && mode !== 'test';

    // FUNÇÃO DE RENDERIZAÇÃO DA COLUNA ESQUERDA (O MODELO VISUAL)
    const renderOriginalDocument = () => {
        if (!activeFile) {
            return (
                <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                    <div className="w-20 h-20 bg-indigo-50 dark:bg-indigo-900/20 rounded-3xl flex items-center justify-center mb-6 text-indigo-500 shadow-inner">
                        <TableCellsIcon className="w-10 h-10" />
                    </div>
                    <h4 className="text-xl font-black text-slate-800 dark:text-white mb-2">Treinar Novo Modelo</h4>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm mb-8 leading-relaxed">
                        Suba um arquivo original ou uma foto de extrato para ensinar o padrão estrutural ao sistema.
                    </p>
                    <FileUploader 
                        id="internal-preprocessor-upload"
                        title="Selecionar Arquivo de Exemplo"
                        onFileUpload={handleInternalUpload}
                        isUploaded={false}
                        uploadedFileName={null}
                        useLocalLoadingOnly={true} 
                    />
                </div>
            );
        }

        if (isImage && activeFile.rawFile) {
            return <ImageRenderer file={activeFile.rawFile} />;
        }

        if (isPdf && activeFile.rawFile) {
            return <PDFRenderer file={activeFile.rawFile} />;
        }

        // Se for planilha (CSV/Excel), mostramos a grade, pois é o "modelo visual" natural desse arquivo
        return <SpreadsheetRenderer data={gridData} detectedMapping={activeMapping} />;
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/95 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Laboratório de Treinamento'} 
                    canApprove={canApprove} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    {/* COLUNA ESQUERDA: DOCUMENTO ORIGINAL (VISUAL PURO) */}
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-[#0B1120] relative overflow-hidden">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex gap-3 items-center z-20 shrink-0 min-h-[56px]">
                            <div className="flex items-center gap-2">
                                <div className="w-2 h-2 rounded-full bg-amber-500 animate-pulse"></div>
                                <span className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">Documento de Origem</span>
                            </div>

                            {isSpreadsheet && activeFile && (
                                <MappingControls 
                                    mapping={activeMapping} 
                                    setMapping={setActiveMapping} 
                                    columnCount={gridData[0]?.length || 0} 
                                    onSimulate={runSimulation}
                                    gridData={gridData}
                                />
                            )}
                        </div>

                        <div className="flex-1 relative">
                            {(isGridLoading || isAiProcessing) && isSpreadsheet ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-900 z-30">
                                     <div className="animate-spin rounded-full h-10 w-10 border-4 border-indigo-500 border-t-transparent mb-4"></div>
                                     <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                         Lendo estrutura do arquivo...
                                     </p>
                                </div>
                            ) : renderOriginalDocument()}
                        </div>
                    </section>

                    {/* COLUNA DIREITA: EXTRAÇÃO E INTELIGÊNCIA */}
                    <section className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] border-l border-slate-200 dark:border-slate-800 shadow-2xl relative z-10">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 flex items-center justify-between shrink-0">
                            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                                <SparklesIcon className="w-4 h-4 text-indigo-500" /> Dados Extraídos (IA)
                            </h4>
                            {activeFile && (
                                <div className="flex items-center gap-2">
                                    <span className="text-[9px] font-bold text-slate-400 bg-white dark:bg-slate-800 px-2 py-0.5 rounded-full border border-slate-200 dark:border-slate-700">
                                        {processedTransactions.length} registros
                                    </span>
                                </div>
                            )}
                        </div>

                        <TeachingBanner isVisible={!!learnedPatternSource} isProcessing={isInferringMapping} onApply={handleApplyCorrectionPattern} />

                        <div className="flex-1 overflow-auto custom-scrollbar">
                            {!activeFile ? (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center opacity-40">
                                    <DocumentArrowDownIcon className="w-12 h-12 mb-3" />
                                    <p className="text-xs font-bold uppercase tracking-widest">Aguardando documento para análise</p>
                                </div>
                            ) : (
                                <SimulatedResultsTable 
                                    transactions={processedTransactions} 
                                    activeMapping={!!activeMapping} 
                                    isTestMode={mode === 'test'} 
                                    editingRowIndex={editingRowIndex} 
                                    editingRowData={editingRowData} 
                                    onStartEdit={startEdit} 
                                    onSaveRow={() => saveRow((original, corrected) => setLearnedPatternSource({ originalRaw: original, corrected }))} 
                                    onCancelEdit={cancelEdit} 
                                    onUpdateEditingData={setEditingRowData} 
                                />
                            )}
                        </div>

                        {/* Controles de mapeamento flutuantes para Imagem/PDF na direita */}
                        {(isImage || isPdf) && activeFile && (
                            <div className="absolute bottom-6 left-6 right-6 p-4 bg-white/90 dark:bg-slate-800/90 backdrop-blur-md rounded-2xl border border-indigo-100 dark:border-indigo-900/50 shadow-2xl flex items-center gap-4 animate-fade-in-up">
                                <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl text-indigo-600">
                                    <TableCellsIcon className="w-5 h-5" />
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Mapeamento de Colunas</p>
                                    <MappingControls 
                                        mapping={activeMapping} 
                                        setMapping={setActiveMapping} 
                                        columnCount={gridData[0]?.length || 0} 
                                        onSimulate={runSimulation}
                                        gridData={gridData}
                                    />
                                </div>
                            </div>
                        )}
                    </section>
                </div>

                {showNameModal && (
                    <div className="fixed inset-0 z-[10000] bg-black/70 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
                        <div className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm border border-white/10 animate-scale-in text-center">
                            <h3 className="text-xl font-black text-slate-800 dark:text-white mb-2">Salvar Padrão</h3>
                            <p className="text-xs text-slate-500 mb-6 font-medium">Dê um nome para este layout para facilitar futuras conciliações.</p>
                            <input type="text" autoFocus value={modelName} onChange={e => setModelName(e.target.value)} className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-white mb-6 outline-none font-bold" placeholder="Ex: Extrato Bradesco - Foto" />
                            <div className="flex gap-3">
                                <button onClick={() => setShowNameModal(false)} className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl font-bold uppercase text-[10px] text-slate-600 dark:text-slate-400">Voltar</button>
                                <button onClick={() => { setShowNameModal(false); handlePersistModel(pendingAction, modelName); }} disabled={isSavingModel || !modelName.trim()} className="flex-1 py-3 bg-indigo-600 text-white rounded-2xl font-bold uppercase text-[10px] shadow-lg shadow-indigo-500/30">
                                    {isSavingModel ? 'Salvando...' : 'Aprovar e Salvar'}
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
};

