    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.slice(0, 50).map(row => row.join(';')).join('\n');
            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: detectedFingerprint, 
                mapping: activeMapping, 
                parsingRules: { 
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [], 
                    rowFilters: [] 
                }, 
                snippet: finalSnippet, 
                lastUsedAt: new Date().toISOString(), 
                status: approvalStatus, 
                approvedBy: approvalStatus === 'approved' ? user.id : undefined, 
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined 
            };
            const saved = await modelService.saveModel(modelData);
            showToast(approvalStatus === 'approved' ? "Modelo aprovado!" : "Layout salvo como rascunho.", "success");
            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions.filter(t => t.isValid));
            } else {
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão estrutural.", "error"); 
        } finally { 
            setIsSavingModel(false); 
        }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, processedTransactions, onSuccess, onClose, showToast]);

    const handleInternalUpload = (content: string, fileName: string, rawFile: File) => {
        setUploadedFile({ content, fileName, rawFile });
    };

    const canApprove = processedTransactions.length > 0 && mode !== 'test';

    // FUNÇÃO DE RENDERIZAÇÃO DA COLUNA ESQUERDA (O MODELO VISUAL DO DOCUMENTO REAL)
    const renderOriginalDocument = () => {
        if (!activeFile) {
            return (
