            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Laboratório de Estruturas'} 
                    canApprove={canApprove} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    {/* COLUNA ESQUERDA: DOCUMENTO ORIGINAL */}
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-[#0B1120] relative overflow-hidden">
                        <div className="px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm flex gap-3 items-center z-20 shrink-0 min-h-[56px]">
