import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { generateFingerprint } from '../services/processingService';
import { FileModel } from '../types';
import { useUI } from '../contexts/UIContext';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);
    const { showToast } = useUI();

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                // EXCEL (CSV Estruturado)
                if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } 
                // CSV / TEXTO / PDF TEXT
                else {
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                        if (lines.length > 0) {
                            const firstLine = lines[0];
                            const delimiter = firstLine.includes(';') ? ';' : (firstLine.includes('\t') ? '\t' : ',');
                            loadedRows = lines.map((l: string) => l.split(delimiter));
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);
                    const sampleContent = activeFile.content || loadedRows.slice(0, 20).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContent);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!activeMapping) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no processamento do laboratório:", err);
                showToast("Erro ao ler estrutura do arquivo.", "error");
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, initialModel, showToast]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import React, { useRef, useState, useEffect, forwardRef, useImperativeHandle } from 'react';
import { UploadIcon, CheckCircleIcon, XMarkIcon } from './Icons';
import { useUI } from '../contexts/UIContext';

let pdfjsLib: any = null;
let XLSX: any = null;

export interface FileUploaderHandle {
    open: () => void;
}

interface FileUploaderProps {
  title: string;
  onFileUpload: (content: string, fileName: string, rawFile: File) => void;
  id: string;
  isUploaded: boolean;
  uploadedFileName: string | null;
  disabled?: boolean;
  onDelete?: () => void;
  customTrigger?: (props: { onClick: (e: React.MouseEvent) => void, disabled: boolean, isParsing: boolean }) => React.ReactNode;
  onParsingStatusChange?: (isParsing: boolean) => void;
  useLocalLoadingOnly?: boolean; 
}

export const FileUploader = forwardRef<FileUploaderHandle, FileUploaderProps>(({ 
    title, 
    onFileUpload, 
    id, 
    isUploaded, 
    uploadedFileName, 
    disabled = false, 
    onDelete, 
    customTrigger,
    onParsingStatusChange,
    useLocalLoadingOnly = false
}, ref) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isParsing, setIsParsing] = useState(false);
  const { setIsLoading, setParsingProgress } = useUI() as any;

  useImperativeHandle(ref, () => ({
      open: () => {
          if (!disabled && !isParsing) {
              fileInputRef.current?.click();
          }
      }
  }));

  const ensureLibsLoaded = async () => {
    try {
        if (!pdfjsLib) {
            try {
                const pdfModule = await import('pdfjs-dist');
                const lib = pdfModule.default || pdfModule;
                if (!lib.GlobalWorkerOptions.workerSrc) {
                    const version = lib.version || '3.11.174';
                    lib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${version}/pdf.worker.min.js`;
                }
                pdfjsLib = lib;
            } catch (e) {}
        }
        if (!XLSX) { try { const mod = await import('xlsx'); XLSX = mod.default || mod; } catch (e) {} }
    } catch (e) {}
  };

  useEffect(() => { ensureLibsLoaded(); }, []);

  useEffect(() => {
      if (onParsingStatusChange) {
          onParsingStatusChange(isParsing);
      }
      if (!useLocalLoadingOnly) {
          setIsLoading(isParsing);
      }
  }, [isParsing, onParsingStatusChange, setIsLoading, useLocalLoadingOnly]);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    processFile(file);
  };

  const processFile = async (file: File) => {
    setIsParsing(true);
    if (setParsingProgress) setParsingProgress({ current: 0, total: 0, label: 'Iniciando...' });

    try {
        await ensureLibsLoaded();
        const fileNameLower = file.name.toLowerCase();
        const fileBuffer = await file.arrayBuffer();
        let extractedText = '';

        if (fileNameLower.endsWith('.pdf')) {
             if (!pdfjsLib) throw new Error("Biblioteca PDF não carregada.");
             const loadingTask = pdfjsLib.getDocument(new Uint8Array(fileBuffer));
             const pdf = await loadingTask.promise;
             const totalPages = pdf.numPages;

             for (let i = 1; i <= totalPages; i++) {
                 if (setParsingProgress) setParsingProgress({ current: i, total: totalPages, label: `Extraindo texto: Página ${i}/${totalPages}` });
                 const page = await pdf.getPage(i);
                 const textContent = await page.getTextContent();
                 const items = textContent.items as any[];
                 extractedText += items.map(it => it.str).join(' ') + '\n';
             }
        } else if (fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls')) {
            if (!XLSX) throw new Error("Excel lib missing");
            const workbook = XLSX.read(new Uint8Array(fileBuffer), { type: 'array' });
            const worksheet = workbook.Sheets[workbook.SheetNames[0]];
            extractedText = XLSX.utils.sheet_to_csv(worksheet, { FS: ";" }); 
        } else {
            extractedText = new TextDecoder('utf-8').decode(fileBuffer);
        }

        onFileUpload(extractedText, file.name, file);
    } catch (error: any) {
        alert(`Erro: ${error.message}`);
    } finally {
        setIsParsing(false);
        if (setParsingProgress) setParsingProgress(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (!disabled && !isParsing) fileInputRef.current?.click();
  };

  if (customTrigger) {
      return (
          <div className="flex-shrink-0">
              <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept=".csv,.txt,.xlsx,.xls,.pdf" />
              {customTrigger({ onClick: handleClick, disabled: disabled || isParsing, isParsing })}
          </div>
      );
  }

  return (
    <div className="flex-shrink-0">
      <input type="file" id={id} ref={fileInputRef} className="hidden" onChange={handleFileChange} disabled={disabled || isParsing} accept=".csv,.txt,.xlsx,.xls,.pdf" />
      <button type="button" onClick={handleClick} disabled={disabled || isParsing} className={`group inline-flex items-center justify-center space-x-1.5 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-wide transition-all ${disabled ? 'bg-slate-100 text-slate-400' : 'text-white bg-emerald-600 hover:bg-emerald-500 shadow-sm'}`}>
         {isParsing ? <><svg className="animate-spin h-3 w-3 text-white mr-1" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg><span>Lendo...</span></> : <><UploadIcon className="w-3 h-3" /><span>{title}</span></>}
      </button>
    </div>
  );
});

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';
import { NameResolver } from '../processors/NameResolver';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V3 - DIGITAL CORE)
 * --------------------------------------------------------------------------
 * Único ponto de entrada para dados brutos.
 * Otimizado para documentos digitais nativos (Excel, CSV, PDF pesquisável).
 */

export interface IngestionResult {
    source: 'upload' | 'gmail';
    transactions: Transaction[];
    strategyUsed: string;
    fingerprint: any;
    appliedModelId?: string;
}

export const IngestionOrchestrator = {
    /**
     * Porta 1: Processamento de Arquivos Físicos (PDF, CSV, Excel, TXT)
     */
    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        const fingerprint = Fingerprinter.generate(content);
        const result = StrategyEngine.process(file.name, content, models, globalKeywords);

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint
        };
    },

    /**
     * Porta 2: Processamento de Dados Virtuais (Gmail / API Sync)
     */
    async processVirtualData(
        sourceName: string,
        data: any[],
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        const yearAnchor = new Date().getFullYear();

        const transactions: Transaction[] = data.map((item, index) => {
            const rawDesc = item.description || item.memo || 'Sem descrição';
            const rawAmount = String(item.amount);

            const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
            const isoDate = DateResolver.resolveToISO(item.date, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);

            return {
                id: `gmail-sync-${Date.now()}-${index}`,
                date: isoDate,
                description: rawDesc.trim(),
                rawDescription: `GMAIL_ORIGIN: ${rawDesc.trim()}`,
                amount: parseFloat(amountStr),
                originalAmount: rawAmount,
                cleanedDescription: cleanedDesc,
                contributionType: item.type || 'PIX'
            };
        }).filter(t => t.date && !isNaN(t.amount));

        const virtualContent = transactions.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        const fingerprint = Fingerprinter.generate(virtualContent) || { source: 'gmail_api' };

        return {
            source: 'gmail',
            transactions,
            strategyUsed: 'GATEWAY_IA_GMAIL',
            fingerprint: { ...fingerprint, is_virtual: true }
        };
    }
};

import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext'; 
import { useAuth } from '../../contexts/AuthContext';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import { CloudArrowUpIcon, DocumentArrowDownIcon, SparklesIcon, TableCellsIcon } from '../Icons';

// Sub-componentes
import { SpreadsheetRenderer } from './preprocessor/SpreadsheetRenderer';
import { PDFRenderer } from './preprocessor/PDFRenderer';
import { SimulatedResultsTable } from './preprocessor/SimulatedResultsTable';
import { MappingControls } from './preprocessor/MappingControls';
import { TeachingBanner } from './preprocessor/TeachingBanner';
import { PreprocessorHeader } from './preprocessor/PreprocessorHeader';

// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords } = useContext(AppContext);

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile: File } | null>(null);
    const activeFile = initialFile || uploadedFile || null;

    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);
    const isSpreadsheet = useMemo(() => /\.(xlsx|xls|csv|txt)$/i.test(activeFile?.fileName || ''), [activeFile]);

    const cleaningKeywords = useMemo(() => [...effectiveIgnoreKeywords, ...contributionKeywords], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading, isAiProcessing, 
        activeMapping, setActiveMapping, detectedFingerprint 
    } = useFileProcessing({ activeFile, initialModel, isPdf });

    const {
        processedTransactions, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ gridData, activeMapping, cleaningKeywords });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ gridData, setGridData, setActiveMapping, showToast });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.slice(0, 100).map(row => row.join(';')).join('\n');
            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: detectedFingerprint, 
                mapping: activeMapping, 
                parsingRules: { 
                    ignoredKeywords: initialModel?.parsingRules?.ignoredKeywords || [], 
                    rowFilters: [] 
                }, 
                snippet: finalSnippet, 
                lastUsedAt: new Date().toISOString(), 
                status: approvalStatus, 
                approvedBy: approvalStatus === 'approved' ? user.id : undefined, 
                approvedAt: approvalStatus === 'approved' ? new Date().toISOString() : undefined 
            };
            const saved = await modelService.saveModel(modelData);
            showToast(approvalStatus === 'approved' ? "Modelo aprovado!" : "Layout salvo como rascunho.", "success");
            if (onSuccess && saved) {
                onSuccess(saved as FileModel, processedTransactions.filter(t => t.isValid));
            } else {
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão estrutural.", "error"); 
        } finally { 
            setIsSavingModel(false); 
        }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, processedTransactions, onSuccess, onClose, showToast]);

    const handleInternalUpload = (content: string, fileName: string, rawFile: File) => {
        setUploadedFile({ content, fileName, rawFile });
    };

    const canApprove = processedTransactions.length > 0 && mode !== 'test';

    const renderOriginalDocument = () => {
        if (!activeFile) {
            return (
                <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
