                    </div>
                )}
            </div>
        </div>,
        document.body
    );
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || {
            dateColumnIndex: -1,
            descriptionColumnIndex: -1,
            amountColumnIndex: -1,
            skipRowsStart: 0
        };

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

        const newTransactions: SafeTransaction[] = [];
        const yearAnchor = DateResolver.discoverAnchorYear(gridData);

        // Aumentado para 200 linhas para garantir visibilidade total da maioria dos extratos no lab
        const sampleData = gridData.slice(0, 200);

        sampleData.forEach((cols, index) => {
            if (!RowValidator.isPotentialRow(cols)) return;

            const isSkipped = index < (skipRowsStart || 0);

            if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                newTransactions.push({ 
                    id: `sim-raw-${index}`, 
                    date: "---", 
                    description: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    rawDescription: cols.join('|'), 
                    amount: 0, 
                    originalAmount: "0.00", 
                    cleanedDescription: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    contributionType: "BRUTO", 
                    sourceIndex: index, 
                    isValid: false, 
                    status: 'pending' 
                });
                return;
            }

            const rawDate = cols[dateColumnIndex] || '';
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex] || '';
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? cols[typeColumnIndex] : '';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);
            const cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
            const finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);

            const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;
            const status: SafeTransaction['status'] = isSkipped ? 'ignored' : (isValid ? 'valid' : 'error');

            newTransactions.push({ 
                id: `sim-${index}`, 
                date: (isValid || status === 'valid') ? isoDate : (rawDate || "---"), 
                description: rawDesc || "---", 
                rawDescription: rawDesc || "---", 
                amount, 
                originalAmount: String(rawAmount), 
                cleanedDescription: cleanedDesc, 
                contributionType: finalType, 
                sourceIndex: index, 
                isValid, 
                status 
            });
        });

        setProcessedTransactions(newTransactions);
    }, [gridData, activeMapping, cleaningKeywords]);

    useEffect(() => {
        const dataKey = `${gridData.length}-${gridData[0]?.length || 0}`;
        const mappingKey = JSON.stringify(activeMapping);

        if (dataKey !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataKey;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = { ...editingRowData, status: 'edited', isValid: true };
                return n;
            });

            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], editingRowData);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

import { useState, useCallback } from 'react';
import { extractStructuredDataByExample } from '../services/geminiService';
import { FileModel, Transaction } from '../types';

/**
 * CONTRATO DE APRENDIZADO (LearningPackage)
 */
export interface LearningPackage {
    model: Partial<FileModel>;
    sampleTransactions: Transaction[];
    confidence: number;
}

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    /**
     * Transforma uma correção manual em um padrão lógico para a IA.
     * Crucial: Esta função agora substitui o gridData integralmente para que a simulação reflita o aprendizado.
     */
    const handleApplyCorrectionPattern = useCallback(async (): Promise<LearningPackage | null> => {
        if (!learnedPatternSource || gridData.length === 0) return null;

        setIsInferringMapping(true);
        try {
            const { originalRaw, corrected } = learnedPatternSource;

            // Pegamos uma amostra maior para o refinamento ser mais preciso (até 500 linhas)
            const rawSnippet = gridData.slice(0, 500).map(row => row.join(';')).join('\n');

            // Instrução ultra-específica baseada no exemplo do usuário
            const userExample = `O usuário corrigiu uma linha manualmente. 
               ENTRADA ORIGINAL: [${originalRaw.join('|')}] 
               SAÍDA DESEJADA: Data: ${corrected.date}, Descrição: ${corrected.cleanedDescription}, Valor: ${corrected.amount}.

               Sua missão: Re-analise TODO o documento abaixo e aplique EXATAMENTE esta lógica de extração para todas as outras linhas similares.`;

            const result = await extractStructuredDataByExample(rawSnippet, userExample);

            if (result?.rows?.length > 0) {
                // Transformamos a resposta da IA (objetos) de volta para o formato de GRADE (array de arrays)
                // Isso "engana" o motor de simulação fazendo-o ler a nova estrutura como se fosse o arquivo original
                const reStructuredGrid = result.rows.map((r: any) => [
                    String(r.date || ''), 
                    String(r.description || ''), 
                    r.amount !== undefined ? String(r.amount) : '',
                    String(r.type || 'OUTROS')
                ]);

                // ATUALIZAÇÃO INTEGRAL DO GRID
                // Ao mudar o gridData, o hook useSimulation disparará automaticamente a re-simulação
                setGridData(reStructuredGrid);

                // Mapeamento fixo pois agora a IA já entregou os dados nas colunas 0, 1 e 2
                const refinedMapping = { 
                    dateColumnIndex: 0, 
                    descriptionColumnIndex: 1, 
                    amountColumnIndex: 2, 
                    typeColumnIndex: 3, 
                    skipRowsStart: 0,
                    skipRowsEnd: 0,
                    decimalSeparator: '.' as const,
                    thousandsSeparator: '' as const
                };

                setActiveMapping(refinedMapping);
                setLearnedPatternSource(null); 
                showToast("IA refinou a extração baseada no seu exemplo!", "success");

                return {
                    model: { mapping: refinedMapping },
                    sampleTransactions: [], 
                    confidence: 0.98
                };
            } else {
                showToast("A IA entendeu o exemplo, mas não encontrou outras linhas similares.", "warning");
            }
            return null;
        } catch (e: any) { 
            showToast("Erro ao aplicar refinamento: " + e.message, "error"); 
            return null;
        } finally { 
            setIsInferringMapping(false); 
        }
    }, [learnedPatternSource, gridData, setGridData, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || {
            dateColumnIndex: -1,
            descriptionColumnIndex: -1,
            amountColumnIndex: -1,
            skipRowsStart: 0
        };

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

        const newTransactions: SafeTransaction[] = [];
        const yearAnchor = DateResolver.discoverAnchorYear(gridData);

        // Processa o grid atual. Se a IA refinou, o grid já está pré-mastigado.
        gridData.forEach((cols, index) => {
            if (!RowValidator.isPotentialRow(cols)) return;

            const isSkipped = index < (skipRowsStart || 0);

            // Se não houver mapeamento e não for grid refinado pela IA
            if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                newTransactions.push({ 
                    id: `sim-raw-${index}`, 
                    date: "---", 
                    description: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    rawDescription: cols.join('|'), 
                    amount: 0, 
                    originalAmount: "0.00", 
                    cleanedDescription: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    contributionType: "BRUTO", 
                    sourceIndex: index, 
                    isValid: false, 
                    status: 'pending' 
                });
                return;
            }

            const rawDate = cols[dateColumnIndex] || '';
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex] || '';
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? cols[typeColumnIndex] : '';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);
            const cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
            const finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);

            const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;
            const status: SafeTransaction['status'] = isSkipped ? 'ignored' : (isValid ? 'valid' : 'error');

            newTransactions.push({ 
                id: `sim-${index}-${Date.now()}`, // Salt para forçar re-render em updates de IA
                date: (isValid || status === 'valid') ? isoDate : (rawDate || "---"), 
                description: rawDesc || "---", 
                rawDescription: rawDesc || "---", 
                amount, 
                originalAmount: String(rawAmount), 
                cleanedDescription: cleanedDesc, 
                contributionType: finalType, 
                sourceIndex: index, 
                isValid, 
                status 
            });
        });

        setProcessedTransactions(newTransactions);
    }, [gridData, activeMapping, cleaningKeywords]);

    // Reatividade aprimorada: Observa mudanças no conteúdo do GRID (importante para refinamento de IA)
    useEffect(() => {
        // Gera um hash simples do conteúdo para detectar mudanças internas no gridData
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);

        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            // Primeiro salvamos localmente para feedback instantâneo
            const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };

            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = updatedTx;
                return n;
            });

            // Disparamos o evento de aprendizado para que a IA possa "olhar" essa correção
            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], updatedTx);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

