import React, { useState, useEffect, useRef } from 'react';
import { XMarkIcon, ArrowPathIcon } from '../../Icons';

export const PDFRenderer: React.FC<{ file?: File }> = ({ file }) => {
    const [pages, setPages] = useState<number[]>([]);
    const [pdfInstance, setPdfInstance] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!file) return;

        const loadPDF = async () => {
            let attempts = 0;
            while (!(window as any).pdfjsLib && attempts < 20) {
                await new Promise(r => setTimeout(r, 200));
                attempts++;
            }

            const pdfjsLib = (window as any).pdfjsLib;
            if (!pdfjsLib) {
                setError("Biblioteca PDF não carregada. Recarregue a página.");
                return;
            }
            try {
                const buffer = await file.arrayBuffer();
                const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
                const pdf = await loadingTask.promise;
                setPdfInstance(pdf);
                setPages(Array.from({ length: pdf.numPages }, (_, i) => i + 1));
            } catch (err: any) { 
                console.error("PDF Load error:", err); 
                setError("Erro ao carregar PDF. Verifique se o arquivo está corrompido.");
            }
        };
        loadPDF();
    }, [file]);

    if (!file) return null;

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center">
                <XMarkIcon className="w-10 h-10 mb-2 opacity-50" />
                <p className="text-xs">{error}</p>
            </div>
        );
    }

    const PageCanvas: React.FC<{ pageNum: number, pdf: any }> = ({ pageNum, pdf }) => {
        const canvasRef = useRef<HTMLCanvasElement>(null);

        useEffect(() => {
            let isMounted = true;

            const render = async () => {
                if (!pdf || !canvasRef.current) return;

                try {
                    const page = await pdf.getPage(pageNum);
                    const viewport = page.getViewport({ scale: 1.5 }); // Aumentado para melhor leitura
                    const canvas = canvasRef.current;
                    if (!canvas) return;

                    const context = canvas.getContext('2d');
                    if (context && isMounted) {
                        canvas.height = viewport.height;
                        canvas.width = viewport.width;
                        await page.render({ canvasContext: context, viewport }).promise;
                    }
                } catch (e) { 
                    if (isMounted) console.error("Render error page " + pageNum, e); 
                }
            };

            render();
            return () => { isMounted = false; };
        }, [pageNum, pdf]);

        return (
            <div className="bg-white p-2 shadow-lg border border-slate-200 mb-6 rounded-md w-fit max-w-full overflow-hidden mx-auto">
                <canvas ref={canvasRef} className="max-w-full h-auto block" />
            </div>
        );
    };

    return (
        <div className="absolute inset-0 overflow-auto custom-scrollbar bg-slate-100 dark:bg-slate-900/50 p-6">
            {pages.map(p => <PageCanvas key={p} pageNum={p} pdf={pdfInstance} />)}
            {pages.length === 0 && !error && (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                    <ArrowPathIcon className="w-8 h-8 animate-spin mb-3 text-indigo-500" />
                    <p className="text-[10px] font-bold uppercase tracking-widest">Processando visual do PDF...</p>
                </div>
            )}
        </div>
    );
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

const generateFingerprint = (t: { 
    transaction_date: string; 
    amount: number; 
    description: string; 
    user_id: string;
    bank_id?: string | null;
}): string => {
    const date = t.transaction_date;
    const amount = Number(t.amount).toFixed(2);
    const desc = (t.description || '').toLowerCase().trim();
    const userId = t.user_id;
    const bankId = t.bank_id || '';
    return `${userId}|${date}|${amount}|${desc}|${bankId}`;
};

const isValidUUID = (uuid: string) => {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(uuid);
};

export const consolidationService = {
    addTransaction: async (transaction: ConsolidatedTransactionInsert) => {
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert({
                transaction_date: transaction.transaction_date,
                amount: transaction.amount,
                description: transaction.description,
                type: transaction.type,
                pix_key: transaction.pix_key,
                source: transaction.source,
                user_id: transaction.user_id,
                bank_id: transaction.bank_id,
                status: 'pending'
            })
            .select()
            .single();

        if (error) throw error;
        return data;
    },

    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];
        const userId = transactions[0].user_id;

        // 1. Busca candidatos existentes para evitar duplicidade no lote
        const { data: existing } = await supabase
            .from('consolidated_transactions')
            .select('transaction_date, amount, description, user_id, bank_id')
            .eq('user_id', userId);

        const existingFps = new Set(existing?.map(t => generateFingerprint(t as any)) || []);

        const toInsert = transactions
            .filter(t => !existingFps.has(generateFingerprint(t as any)))
            .map(t => ({
                transaction_date: t.transaction_date,
                amount: t.amount,
                description: t.description,
                type: t.type,
                pix_key: t.pix_key,
                source: t.source,
                user_id: t.user_id,
                bank_id: t.bank_id,
                status: 'pending' as const
            }));

        if (toInsert.length === 0) return [];

        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert(toInsert)
            .select();

        if (error) {
            console.error("Erro no batch insert:", error);
            throw error;
        }
        return data;
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!bankId) {
                const { error } = await supabase
                    .from('consolidated_transactions')
                    .delete()
                    .eq('user_id', userId)
                    .eq('status', 'pending');
                if (error) throw error;
                return;
            }

            if (!isValidUUID(bankId)) return;

            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending')
                .eq('bank_id', bankId);

            if (error) throw error;
        } catch (error) {
            console.error("[Consolidation] Erro na exclusão:", error);
            throw error;
        }
    },

    getPendingTransactions: async (userId: string) => {
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .select('*')
            .eq('user_id', userId)
            .eq('status', 'pending')
            .order('transaction_date', { ascending: false });
        if (error) throw error;
        return data;
    }
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v10';

const getConsolidatedLocalModels = async (): Promise<FileModel[]> => {
    try {
        const currentModels = await get(PERSISTENT_STORAGE_KEY);
        return Array.isArray(currentModels) ? currentModels : [];
    } catch (e) { 
        return []; 
    }
};

const mapDbRowToModel = (row: any): FileModel => ({
    id: row.id,
    name: row.name,
    user_id: row.user_id,
    version: row.version || 1,
    lineage_id: row.lineage_id || row.id,
    is_active: row.is_active,
    status: row.status || 'draft',
    fingerprint: typeof row.fingerprint === 'string' ? JSON.parse(row.fingerprint) : row.fingerprint,
    mapping: typeof row.mapping === 'string' ? JSON.parse(row.mapping) : row.mapping,
    parsingRules: row.parsing_rules ? (typeof row.parsing_rules === 'string' ? JSON.parse(row.parsing_rules) : row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
    snippet: row.snippet,
    createdAt: row.created_at || new Date().toISOString(),
    lastUsedAt: row.last_used_at
});

export const modelService = {
    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            // 1. Desativa versões antigas da mesma linhagem
            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id);
            }

            // 2. PAYLOAD MÍNIMO E EXATO (SNAKE_CASE PARA O DB)
            // Removemos campos calculados ou metadados que o Supabase gera automaticamente
            const dbPayload = {
                name: model.name,
                user_id: model.user_id,
                version: model.version,
                lineage_id: model.lineage_id,
                is_active: true,
                status: model.status,
                fingerprint: model.fingerprint,
                mapping: model.mapping,
                parsing_rules: model.parsingRules, // Garante snake_case
                snippet: model.snippet || null
            };

            // Usamos apenas o insert básico sem forçar colunas na query string
            const { data, error } = await supabase
                .from('file_models')
                .insert(dbPayload)
                .select()
                .single();

            if (error) {
                console.error("Erro Supabase (Save):", error.message, error.details);
                throw error;
            }

            return mapDbRowToModel(data);

        } catch (error: any) {
            Logger.error("Falha ao salvar na nuvem, tentando fallback local", error);

            // Fallback local caso a nuvem falhe (evita que o usuário perca o trabalho)
            const localId = `local-${Date.now()}`;
            const newModel: FileModel = {
                ...model,
                id: localId,
                createdAt: new Date().toISOString()
            };

            const currentLocals = await getConsolidatedLocalModels();
            const updatedLocals = [newModel, ...currentLocals.filter(m => m.lineage_id !== model.lineage_id)];
            await set(PERSISTENT_STORAGE_KEY, updatedLocals);

            return newModel;
        }
    },

    getUserModels: async (userId: string): Promise<FileModel[]> => {
        let remoteModels: FileModel[] = [];
        try {
            // Busca simplificada para evitar erro 400
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('is_active', true);

            if (error) {
                console.error("Erro Supabase (List):", error.message);
            } else if (data) {
                remoteModels = data.map(mapDbRowToModel);
            }
        } catch (e) {
            console.error("Falha ao ler modelos remotos", e);
        }

        const localModels = await getConsolidatedLocalModels();
        const uniqueModels = new Map<string, FileModel>();

        [...remoteModels, ...localModels].forEach(m => {
            const existing = uniqueModels.get(m.lineage_id);
            if (!existing || new Date(m.createdAt) > new Date(existing.createdAt)) {
                uniqueModels.set(m.lineage_id, m);
            }
        });

        return Array.from(uniqueModels.values());
    },

    deleteModel: async (id: string) => {
        if (id.startsWith('local-')) {
            const current = await getConsolidatedLocalModels();
            await set(PERSISTENT_STORAGE_KEY, current.filter(m => m.id !== id));
            return true;
        }
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        return !error;
    },

    getAllModelsAdmin: async (): Promise<(FileModel & { user_email?: string })[]> => {
        try {
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            return (data || []).map(mapDbRowToModel);
        } catch (e) {
            return await getConsolidatedLocalModels();
        }
    },

    updateModelName: async (id: string, name: string) => {
        if (id.startsWith('local-')) {
            const current = await getConsolidatedLocalModels();
            await set(PERSISTENT_STORAGE_KEY, current.map(m => m.id === id ? {...m, name} : m));
            return true;
        }
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        return !error;
    }
};

