import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[];
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
            (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
            (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter)
        );
    },
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return [];

        const matchingModel = models.find(m => 
            (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
            (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
            (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter)
        );

        if (!matchingModel) return [];

        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter;

        // REGRA DE OURO: Para modelos aprendidos, NÃO usamos globalKeywords. 
        // Usamos apenas o que o usuário definiu no Laboratório.
        const modelKeywords = matchingModel.parsingRules?.ignoredKeywords || [];

        const dataLines = lines.slice(skipRowsStart || 0);

        dataLines.forEach((line, index) => {
            const cols = line.split(delimiter);

            // Validação de largura de linha
            const requiredIdx = Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex);
            if (cols.length <= requiredIdx) return;

            const rawDate = (cols[dateColumnIndex] || '').trim();
            const rawDesc = (cols[descriptionColumnIndex] || '').trim();
            const rawAmount = (cols[amountColumnIndex] || '').trim();

            // IGNORA APENAS SE FOR UMA LINHA DE CONTROLE ÓBVIA (Saldo/Total)
            // Se o usuário mapeou, ele quer o dado.
            if (NameResolver.isControlRow(rawDesc) && index < 3) return;

            // RESOLUÇÃO DE VALOR RIGOROSA
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);

            // RESOLUÇÃO DE DATA RIGOROSA
            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);

            if (isoDate && !isNaN(amount)) {
                // LIMPEZA DE NOME: Apenas o que o modelo pede
                const cleanedDesc = NameResolver.clean(rawDesc, modelKeywords);

                transactions.push({
                    id: `db-${matchingModel.id}-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc,
                    rawDescription: rawDesc,
                    amount: amount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedDesc,
                    contributionType: typeColumnIndex !== undefined && typeColumnIndex !== -1 
                        ? (cols[typeColumnIndex] || '').trim().toUpperCase() 
                        : TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const SicoobStrategy: BankStrategy = {
    name: 'Sicoob (Extrato PDF)',
    canHandle: (filename, content) => content.toUpperCase().includes('SICOOB'),
    parse: (content, yearAnchor) => {
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/);
        const headerRegex = /^(\d{2}\/\d{2})\s+(.*?)\s+([\d.,]+[CD]?\*?)$/;
        lines.forEach((line, idx) => {
            const match = line.trim().match(headerRegex);
            if (match) {
                const amount = parseFloat(AmountResolver.clean(match[3]));
                if (!isNaN(amount)) {
                    transactions.push({
                        id: `sicoob-${idx}-${Date.now()}`,
                        date: DateResolver.resolveToISO(match[1], yearAnchor),
                        description: match[2].trim(),
                        rawDescription: match[2].trim(),
                        amount,
                        originalAmount: match[3],
                        cleanedDescription: NameResolver.clean(match[2]),
                        contributionType: TypeResolver.resolveFromDescription(match[2])
                    });
                }
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amount = parseFloat(AmountResolver.clean(row[aIdx]));
            if (!date || isNaN(amount) || amount === 0) return null;
            const desc = row[nIdx] || 'S/D';

            return {
                id: `gen-${i}-${Date.now()}`,
                date,
                amount,
                description: desc,
                rawDescription: desc,
                originalAmount: row[aIdx],
                cleanedDescription: NameResolver.clean(desc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(desc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, SicoobStrategy, GenericStrategy],
    process: (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel) => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        if (overrideModel) {
            return { 
                transactions: DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], []), 
                strategyName: overrideModel.name 
            };
        }

        const fileFp = Fingerprinter.generate(content);
        if (fileFp && DatabaseModelStrategy.canHandle(filename, content, models)) {
            const res = DatabaseModelStrategy.parse(content, yearAnchor, models, []);
            if (res.length > 0) {
                const modelName = models.find(m => 
                    m.fingerprint.headerHash === fileFp.headerHash || 
                    m.fingerprint.structuralPattern === fileFp.structuralPattern
                )?.name || 'Modelo Aprendido';

                return { transactions: res, strategyName: modelName };
            }
        }

        for (const s of StrategyEngine.strategies) {
            if (s.name === 'Genérico' || s.name === 'Modelo Aprendido') continue;
            if (s.canHandle(filename, content, models)) {
                const res = s.parse(content, yearAnchor, models, globalKeywords);
                if (res.length > 0) return { transactions: res, strategyName: s.name };
            }
        }

        return { transactions: GenericStrategy.parse(content, yearAnchor, models, globalKeywords), strategyName: 'Genérico' };
    }
};

