export const findMatchingModel = (content: string, models: FileModel[]): { model: FileModel, score: number } | null => {
    if (!models || models.length === 0) return null;

    const fileFp = Fingerprinter.generate(content);
    if (!fileFp) return null;

    let bestMatch: FileModel | null = null;
    let bestScore = 0;

    for (const model of models) {
        if (!model.is_active) continue;

        const modelFp = model.fingerprint;
        let score = 0;

        // CRITÉRIO 1: HASH DE CABEÇALHO (Peso máximo)
        if (modelFp.headerHash && fileFp.headerHash && modelFp.headerHash === fileFp.headerHash) {
            score += 80;
        }

        // CRITÉRIO 2: PADRÃO ESTRUTURAL
        if (modelFp.structuralPattern && fileFp.structuralPattern && modelFp.structuralPattern === fileFp.structuralPattern) {
            score += 15;
        }

        // CRITÉRIO 3: CONTAGEM DE COLUNAS
        if (modelFp.columnCount === fileFp.columnCount) {
            score += 5;
        }

        if (score > bestScore && score >= 80) {
            bestScore = score;
            bestMatch = model;
        }
    }

    return bestMatch ? { model: bestMatch, score: bestScore } : null;
};

export const processFileContent = (content: string, fileName: string, models: FileModel[] = [], globalKeywords: string[] = []): { transactions: Transaction[], method: string, appliedModel?: any } => {
    let targetModel: FileModel | undefined;
    let appliedModelMeta: any = undefined;

    try {
        const matchResult = findMatchingModel(content, models);
        if (matchResult) {
            observationService.addLog(fileName, matchResult.model, matchResult.score);
            targetModel = matchResult.model;
        }
    } catch (e) {
        console.warn("[Processing] Erro na verificação de modelos:", e);
    }

    // Se houver um modelo alvo, passamos o array de keywords globais VAZIO 
    // para que a StrategyEngine use apenas as regras do modelo.
    const effectiveKeywords = targetModel ? [] : globalKeywords;

    const result = StrategyEngine.process(fileName, content, models, effectiveKeywords, targetModel);

    if (targetModel) {
        appliedModelMeta = {
            id: targetModel.id,
            name: targetModel.name,
            confidenceScore: 100
        };
    }

    return {
        transactions: result.transactions,
        method: targetModel ? targetModel.name : result.strategyName,
        appliedModel: appliedModelMeta
    };
};

