};

const isValidUUID = (uuid: string) => {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(uuid);
};

export const consolidationService = {
    addTransaction: async (transaction: ConsolidatedTransactionInsert) => {
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert({
                transaction_date: transaction.transaction_date,
                amount: transaction.amount,
                description: transaction.description,
                type: transaction.type,
                pix_key: transaction.pix_key,
                source: transaction.source,
                user_id: transaction.user_id,
                bank_id: transaction.bank_id,
                status: 'pending'
            })
            .select()
            .single();

        if (error) throw error;
        return data;
    },

    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        // Simplesmente inserimos tudo. Deixamos a lógica de "já existe" para o LaunchService 
        // ou permitimos duplicados se o usuário subir arquivos propositalmente.
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert(transactions.map(t => ({
                transaction_date: t.transaction_date,
                amount: t.amount,
                description: t.description,
                type: t.type,
                pix_key: t.pix_key,
                source: t.source,
                user_id: t.user_id,
                bank_id: t.bank_id,
                status: 'pending' as const
            })))
            .select();

        if (error) {
            console.error("Erro no batch insert:", error);
            throw error;
        }
        return data;
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!bankId) {
                const { error } = await supabase
                    .from('consolidated_transactions')
                    .delete()
                    .eq('user_id', userId)
                    .eq('status', 'pending');
                if (error) throw error;
                return;
            }

            if (!isValidUUID(bankId)) return;

            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending')
                .eq('bank_id', bankId);

            if (error) throw error;
        } catch (error) {
            console.error("[Consolidation] Erro na exclusão:", error);
            throw error;
        }
    },

    getPendingTransactions: async (userId: string) => {
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .select('*')
            .eq('user_id', userId)
            .eq('status', 'pending')
            .order('transaction_date', { ascending: false });
        if (error) throw error;
        return data;
    }
};

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[];
}

/**
 * ESTRATÉGIA DE MODELO APRENDIDO (MODO PASS-THROUGH)
 * Fiel 100% ao que o usuário configurou no Laboratório.
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
            (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
            (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter)
        );
    },
    parse: (content, yearAnchor, models) => {
        if (!models || models.length === 0) return [];
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return [];

        const matchingModel = models.find(m => 
            (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
            (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
            (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter)
        );

        if (!matchingModel) return [];

        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter;

        // Pula apenas as linhas de cabeçalho definidas pelo modelo
        const dataLines = lines.slice(skipRowsStart || 0);

        dataLines.forEach((line, index) => {
            const cols = line.split(delimiter);

            // Verificação mínima de largura de colunas mapeadas
            const maxIdx = Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex || 0);
            if (cols.length <= maxIdx && cols.length < 2) return;

            // EXTRAÇÃO BRUTA (IDÊNTICA AO LABORATÓRIO)
            const rawDate = cols[dateColumnIndex] || '';
            const rawDesc = cols[descriptionColumnIndex] || '';
            const rawAmount = cols[amountColumnIndex] || '';
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex] || '') : '';

            // VALOR: Conversão técnica mínima para permitir cálculos, mas preservando o sinal
            // Não usamos AmountResolver.clean aqui para evitar perdas de precisão ou interpretação de milhar errada
            let valStr = rawAmount.replace(/[R$\s]/g, '').replace('.', '').replace(',', '.');
            // Caso o replace do ponto tenha sido agressivo (ex: 10.50 -> 1050), corrigimos para manter a lógica do parseFloat
            if (!rawAmount.includes(',')) {
                 valStr = rawAmount.replace(/[R$\s]/g, '');
            }

            const numericValue = parseFloat(valStr) || 0;

            // DATA: Mantemos a string original para exibição se o resolver falhar, 
            // garantindo que NENHUMA linha seja perdida por "data inválida"
            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor) || rawDate;

            transactions.push({
                id: `db-${matchingModel.id}-${index}-${Date.now()}`,
                date: isoDate,
                description: rawDesc, // Fiel ao original
                rawDescription: rawDesc,
                amount: numericValue,
                originalAmount: rawAmount,
                cleanedDescription: rawDesc, // Em modelo, não existe limpeza, apenas o dado
                contributionType: rawType.toUpperCase() || TypeResolver.resolveFromDescription(rawDesc)
            });
        });
        return transactions;
    }
};

export const SicoobStrategy: BankStrategy = {
    name: 'Sicoob (Extrato PDF)',
    canHandle: (filename, content) => content.toUpperCase().includes('SICOOB'),
    parse: (content, yearAnchor) => {
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/);
        const headerRegex = /^(\d{2}\/\d{2})\s+(.*?)\s+([\d.,]+[CD]?\*?)$/;
        lines.forEach((line, idx) => {
            const match = line.trim().match(headerRegex);
            if (match) {
                const amount = parseFloat(AmountResolver.clean(match[3]));
                if (!isNaN(amount)) {
                    transactions.push({
                        id: `sicoob-${idx}-${Date.now()}`,
                        date: DateResolver.resolveToISO(match[1], yearAnchor),
                        description: match[2].trim(),
                        rawDescription: match[2].trim(),
                        amount,
                        originalAmount: match[3],
                        cleanedDescription: NameResolver.clean(match[2]),
                        contributionType: TypeResolver.resolveFromDescription(match[2])
                    });
                }
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amount = parseFloat(AmountResolver.clean(row[aIdx]));
            if (!date || isNaN(amount) || amount === 0) return null;
            const desc = row[nIdx] || 'S/D';

            return {
                id: `gen-${i}-${Date.now()}`,
                date,
                amount,
                description: desc,
                rawDescription: desc,
                originalAmount: row[aIdx],
                cleanedDescription: NameResolver.clean(desc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(desc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, SicoobStrategy, GenericStrategy],
    process: (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel) => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        if (overrideModel) {
            return { 
                transactions: DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], []), 
                strategyName: overrideModel.name 
            };
        }

        if (DatabaseModelStrategy.canHandle(filename, content, models)) {
            const res = DatabaseModelStrategy.parse(content, yearAnchor, models, []);
            if (res.length > 0) {
                const matched = models.find(m => {
                    const fileFp = Fingerprinter.generate(content);
                    return fileFp && (m.fingerprint.headerHash === fileFp.headerHash || m.fingerprint.structuralPattern === fileFp.structuralPattern);
                });
                return { transactions: res, strategyName: matched?.name || 'Modelo Aprendido' };
            }
        }

        for (const s of StrategyEngine.strategies) {
            if (s.name === 'Genérico' || s.name === 'Modelo Aprendido') continue;
            if (s.canHandle(filename, content, models)) {
                const res = s.parse(content, yearAnchor, models, globalKeywords);
                if (res.length > 0) return { transactions: res, strategyName: s.name };
            }
        }

        return { transactions: GenericStrategy.parse(content, yearAnchor, models, globalKeywords), strategyName: 'Genérico' };
    }
};

import { Contributor, MatchResult, Church, Transaction, ReconciliationStatus, MatchMethod } from '../../types';
import { normalizeString, parseDate, PLACEHOLDER_CHURCH, cleanTransactionDescriptionForDisplay } from '../utils/parsingUtils';

/**
 * Calcula a similaridade focada apenas no NOME.
 */
export const calculateNameSimilarity = (description: string, contributor: Contributor, ignoreKeywords: string[] = []): number => {
    // Se não houver keywords (caso do Modelo), a comparação é direta
    const txNorm = normalizeString(description, ignoreKeywords);
    const contribNorm = contributor.normalizedName || normalizeString(contributor.name, ignoreKeywords);

    if (!txNorm || !contribNorm) return 0;

    const txTokens = txNorm.split(/\s+/).filter(t => t.length > 2);
    const contribTokens = contribNorm.split(/\s+/).filter(t => t.length > 2);

    if (txTokens.length === 0 || contribTokens.length === 0) {
        // Fallback para match exato se os nomes forem curtos
        return txNorm === contribNorm ? 100 : 0;
    }

    const txSet = new Set(txTokens);
    const contribSet = new Set(contribTokens);
    const intersection = [...txSet].filter(w => contribSet.has(w)).length;

    return (2 * intersection) / (txSet.size + contribSet.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: any[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: any[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const contributorsByChurch = new Map<string, any[]>();

    contributorFiles.forEach((file: any) => {
        const churchId = file.church.id;
        const list = file.contributors.map((c: any) => ({ 
            ...c, 
            church: file.church,
            _churchId: churchId,
            _internalId: c.id || `contrib-${churchId}-${normalizeString(c.name).replace(/\s/g, '')}`
        }));
        contributorsByChurch.set(churchId, list);
    });

    const allContributorsFlat = Array.from(contributorsByChurch.values()).flat();
    const finalResults: MatchResult[] = [];
    const usedContributors = new Set<string>();

    transactions.forEach(tx => {
        // Se a transação vem de um banco de dados de modelo, o customIgnoreKeywords já foi forçado para [] no processFileContent
        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);

        let matchResult: MatchResult = {
            transaction: tx,
            contributor: null,
            status: ReconciliationStatus.UNIDENTIFIED,
            church: PLACEHOLDER_CHURCH,
            similarity: 0,
            contributionType: tx.contributionType
        };

        const learned = learnedAssociations.find((la: any) => la.normalizedDescription === txDescNormalized);
        if (learned && learned.churchId) {
            const churchList = contributorsByChurch.get(learned.churchId) || [];
            const matchedContrib = churchList.find((c: any) => 
                normalizeString(c.name, customIgnoreKeywords) === learned.contributorNormalizedName
            );

            if (matchedContrib) {
                usedContributors.add(matchedContrib._internalId);
                matchResult = {
                    ...matchResult,
                    status: ReconciliationStatus.IDENTIFIED,
                    contributor: matchedContrib,
                    church: matchedContrib.church,
                    matchMethod: MatchMethod.LEARNED,
                    similarity: 100,
                    contributorAmount: matchedContrib.amount,
                    contributionType: matchedContrib.contributionType || tx.contributionType
                };
                finalResults.push(matchResult);
                return;
            }
        }

        let bestMatch: any = null;
        let highestScore = 0;

        allContributorsFlat.forEach((contrib: any) => {
            const score = calculateNameSimilarity(tx.description, contrib, customIgnoreKeywords);
            if (score > highestScore) {
                highestScore = score;
                bestMatch = contrib;
            }
        });

        if (bestMatch && highestScore >= 90) {
            usedContributors.add(bestMatch._internalId);
            matchResult = {
                ...matchResult,
                status: ReconciliationStatus.IDENTIFIED,
                contributor: bestMatch,
                church: bestMatch.church,
                matchMethod: MatchMethod.AI,
                similarity: highestScore,
                contributorAmount: bestMatch.amount,
                contributionType: bestMatch.contributionType || tx.contributionType
            };
        } else if (bestMatch && highestScore >= 25) {
            matchResult.suggestion = bestMatch;
            matchResult.similarity = highestScore;
        }

        finalResults.push(matchResult);
    });

    allContributorsFlat.forEach((contrib: any) => {
        if (!usedContributors.has(contrib._internalId)) {
            finalResults.push({
                transaction: {
                    id: `ghost-${contrib._internalId}`,
                    date: contrib.date || new Date().toISOString().split('T')[0],
                    description: contrib.name,
                    rawDescription: contrib.name,
                    amount: 0,
                    cleanedDescription: contrib.name,
                    contributionType: contrib.contributionType,
                    originalAmount: "0.00"
                },
                contributor: { ...contrib, cleanedName: contrib.name },
                status: ReconciliationStatus.PENDING,
                church: contrib.church,
                matchMethod: MatchMethod.MANUAL,
                similarity: 0,
                contributorAmount: contrib.amount
            });
        }
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): Record<string, MatchResult[]> => {
    const grouped: Record<string, MatchResult[]> = {};
    results.forEach(r => {
        let key = 'unidentified';
        if ((r.status === ReconciliationStatus.IDENTIFIED || r.status === ReconciliationStatus.PENDING) && r.church?.id) {
            key = r.church.id;
        }
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

