import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[];
}

/**
 * ESTRATÉGIA DE MODELO APRENDIDO (V6 - ROBUSTA)
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => {
            // 1. Check por DNA de Cabeçalho (Prioridade Máxima)
            if (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) return true;

            // 2. Check por Padrão Estrutural (DNA de Colunas)
            if (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') return true;

            // 3. Check por Geometria Simples (Fallback de Segurança)
            if (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter) {
                // Se a geometria bate e não temos nada melhor, arriscamos se tivermos confiança topológica
                if (m.fingerprint.dataTopology === fileFp.dataTopology) return true;
            }

            return false;
        });
    },
    parse: (content, yearAnchor, models) => {
        if (!models || models.length === 0) return [];
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return [];

        const matchingModel = models.find(m => 
            (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
            (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
            (m.fingerprint.columnCount === fileFp.columnCount && m.fingerprint.delimiter === fileFp.delimiter)
        );

        if (!matchingModel) return [];

        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter;

        const dataLines = lines.slice(skipRowsStart || 0);

        dataLines.forEach((line, index) => {
            const cols = line.split(delimiter);

            // Validação de largura da linha para evitar processar fragmentos
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawDate = (cols[dateColumnIndex] || '').trim();
            const rawDesc = (cols[descriptionColumnIndex] || '').trim();
            const rawAmount = (cols[amountColumnIndex] || '').trim();
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex] || '').trim() : '';

            // Limpeza básica de valor
            let cleanVal = rawAmount.replace(/[R$\s]/g, '');
            const isNegative = cleanVal.includes('-') || cleanVal.includes('(') || cleanVal.toUpperCase().endsWith('D');

            if (cleanVal.includes(',') && cleanVal.includes('.')) {
                cleanVal = cleanVal.replace(/\./g, '').replace(',', '.');
            } else if (cleanVal.includes(',')) {
                cleanVal = cleanVal.replace(',', '.');
            }

            const numericValue = parseFloat(cleanVal.replace(/[^0-9.-]/g, '')) * (isNegative ? -1 : 1);
            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor) || rawDate;

            if (rawDesc && !isNaN(numericValue)) {
                transactions.push({
                    id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc, 
                    rawDescription: rawDesc,
                    amount: numericValue,
                    originalAmount: rawAmount,
                    cleanedDescription: rawDesc, 
                    contributionType: rawType.toUpperCase() || TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const SicoobStrategy: BankStrategy = {
    name: 'Sicoob (Extrato PDF)',
    canHandle: (filename, content) => content.toUpperCase().includes('SICOOB'),
    parse: (content, yearAnchor) => {
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/);
        const headerRegex = /^(\d{2}\/\d{2})\s+(.*?)\s+([\d.,]+[CD]?\*?)$/;
        lines.forEach((line, idx) => {
            const match = line.trim().match(headerRegex);
            if (match) {
                const amount = parseFloat(AmountResolver.clean(match[3]));
                if (!isNaN(amount)) {
                    transactions.push({
                        id: `sicoob-${idx}-${Date.now()}`,
                        date: DateResolver.resolveToISO(match[1], yearAnchor),
                        description: match[2].trim(),
                        rawDescription: match[2].trim(),
                        amount,
                        originalAmount: match[3],
                        cleanedDescription: NameResolver.clean(match[2]),
                        contributionType: TypeResolver.resolveFromDescription(match[2])
                    });
                }
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amount = parseFloat(AmountResolver.clean(row[aIdx]));
            if (!date || isNaN(amount) || amount === 0) return null;
            const desc = row[nIdx] || 'S/D';

            return {
                id: `gen-${i}-${Date.now()}`,
                date,
                amount,
                description: desc,
                rawDescription: desc,
                originalAmount: row[aIdx],
                cleanedDescription: NameResolver.clean(desc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(desc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, SicoobStrategy, GenericStrategy],
    process: (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel) => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        if (overrideModel) {
            return { 
                transactions: DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], []), 
                strategyName: overrideModel.name 
            };
        }

        if (DatabaseModelStrategy.canHandle(filename, content, models)) {
            const res = DatabaseModelStrategy.parse(content, yearAnchor, models, []);
            if (res.length > 0) {
                const matched = models.find(m => {
                    const fileFp = Fingerprinter.generate(content);
                    return fileFp && (m.fingerprint.headerHash === fileFp.headerHash || m.fingerprint.structuralPattern === fileFp.structuralPattern);
                });
                return { transactions: res, strategyName: matched?.name || 'Modelo Aprendido' };
            }
        }

        for (const s of StrategyEngine.strategies) {
            if (s.name === 'Genérico' || s.name === 'Modelo Aprendido') continue;
            if (s.canHandle(filename, content, models)) {
                const res = s.parse(content, yearAnchor, models, globalKeywords);
                if (res.length > 0) return { transactions: res, strategyName: s.name };
            }
        }

        return { transactions: GenericStrategy.parse(content, yearAnchor, models, globalKeywords), strategyName: 'Genérico' };
    }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (msg.includes("429") || msg.includes("quota")) {
            if (retries > 0) {
                await new Promise(r => setTimeout(r, delay * 2));
                return callWithSimpleRetry(fn, retries - 1, delay * 2);
            }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * IA TRAINER V2: Especialista em PDFs complexos.
 * Força a extração de índices literais sem "limpeza inteligente" prévia.
 */
export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `AJA COMO UM ARQUITETO DE DADOS. Analise este extrato (provavelmente extraído de um PDF) e identifique os índices de colunas (0, 1, 2...).

        DADOS BRUTOS (DELIMITADOS POR PONTO E VÍRGULA):
        ${sampleText.substring(0, 6000)}

        SUAS REGRAS DE OURO:
        1. DATA: Procure o índice que contém datas (DD/MM ou DD/MM/AAAA).
        2. DESCRIÇÃO: Procure a coluna com mais texto. NÃO RECOMENDE LIMPEZA. Pegue o índice da coluna bruta.
        3. VALOR: Procure a coluna que contém números financeiros. Identifique se o valor está em uma coluna única ou se há uma coluna de "Tipo" (C/D) ao lado.
        4. CABEÇALHO: Identifique a partir de qual linha começam os dados REAIS (ignore títulos do banco e saldos iniciais).

        RETORNE APENAS O JSON:
        {
          "dateColumnIndex": number,
          "descriptionColumnIndex": number,
          "amountColumnIndex": number,
          "typeColumnIndex": number | null,
          "skipRowsStart": number,
          "confidence": number (0 a 1)
        }`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0.1,
                responseMimeType: "application/json"
            }
        });

        return response.text ? JSON.parse(response.text) : null;
    });
};

export const extractDataFromVisual = async (file: File): Promise<string> => {
    const base64Data = await new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });

    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType: file.type, data: base64Data } },
                    { text: `Transcreva este documento financeiro com fidelidade absoluta para JSON.` }
                ]
            },
            config: { temperature: 0 }
        });
        let text = response.text || "{\"rows\": []}";
        if (text.includes('```json')) text = text.split('```json')[1].split('```')[0];
        return text.trim();
    });
};

export const extractStructuredDataByExample = async (rawSnippet: string, userExample: string): Promise<{ rows: any[] }> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Re-processe este documento usando o padrão literal fornecido.\nEXEMPLO: ${userExample}\nDOCUMENTO:\n${rawSnippet.substring(0, 20000)}`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json"
            }
        });
        return response.text ? JSON.parse(response.text) : { rows: [] };
    });
};

export const getAISuggestion = async (transaction: Transaction, contributors: Contributor[]): Promise<string> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise: "${transaction.description}". Qual contribuinte melhor se encaixa? Lista: [${contributors.map(c => c.name).join(', ')}]. Responda apenas o nome ou "Nenhuma sugestão clara".`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0.1 }
        });
        return response.text ? response.text.trim() : "Nenhuma sugestão clara";
    });
};

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { generateFingerprint } from '../services/processingService';
import { FileModel } from '../types';
import { useUI } from '../contexts/UIContext';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);
    const { showToast } = useUI();

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            processingRef.current = null;
            return;
        }

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                // EXCEL (CSV Estruturado)
                if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } 
                // CSV / TEXTO / PDF TEXT
                else {
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        // PDF TEXT EXTRACTION NORMALIZER
                        // PDFs costumam vir com múltiplos espaços separando colunas. 
                        // Vamos converter sequências de 3 ou mais espaços em um delimitador fixo.
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);

                        if (lines.length > 0) {
                            // Se for PDF (identificado por metadados ou extension), normalizamos os espaços para virar colunas
                            const isLikelyPdfText = isPdf || content.includes('  ');

                            loadedRows = lines.map((l: string) => {
                                if (isLikelyPdfText && !l.includes(';') && !l.includes('\t')) {
                                    // Transforma 2 ou mais espaços em ponto e vírgula para criar colunas virtuais
                                    return l.replace(/\s{2,}/g, ';').split(';');
                                }
                                const delimiter = l.includes(';') ? ';' : (l.includes('\t') ? '\t' : ',');
                                return l.split(delimiter);
                            });
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);
                    // Fingerprint deve ser gerado a partir do conteúdo normalizado para garantir match futuro
                    const sampleContentForFp = loadedRows.slice(0, 30).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContentForFp);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!activeMapping) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no processamento do laboratório:", err);
                showToast("Erro ao ler estrutura do arquivo.", "error");
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, initialModel, showToast]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || {
            dateColumnIndex: -1,
            descriptionColumnIndex: -1,
            amountColumnIndex: -1,
            skipRowsStart: 0
        };

        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

        const newTransactions: SafeTransaction[] = [];
        const yearAnchor = DateResolver.discoverAnchorYear(gridData);

        gridData.forEach((cols, index) => {
            if (!RowValidator.isPotentialRow(cols)) return;

            const isSkipped = index < (skipRowsStart || 0);

            // MODO BRUTO: Se nada está mapeado, mostra o que tem
            if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                newTransactions.push({ 
                    id: `sim-raw-${index}`, 
                    date: "---", 
                    description: cols.filter(c => !!c).join(' | ').substring(0, 80), 
                    rawDescription: cols.join('|'), 
                    amount: 0, 
                    originalAmount: "0.00", 
                    cleanedDescription: cols.filter(c => !!c).join(' | '), 
                    contributionType: "BRUTO", 
                    sourceIndex: index, 
                    isValid: false, 
                    status: 'pending' 
                });
                return;
            }

            const rawDate = (cols[dateColumnIndex] || '').trim();
            const rawDesc = (cols[descriptionColumnIndex] || '').trim();
            const rawAmount = (cols[amountColumnIndex] || '').trim();
            const rawType = typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex] || '').trim() : '';

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amount = parseFloat(amountStr);

            // NO LABORATÓRIO NÃO LIMPAMOS NADA AUTOMATICAMENTE
            // O usuário deve ver o que a coluna contém de verdade para treinar certo
            const displayDesc = rawDesc || "---";

            const finalType = rawType.toUpperCase() || TypeResolver.resolveFromDescription(rawDesc);

            const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;
            const status: SafeTransaction['status'] = isSkipped ? 'ignored' : (isValid ? 'valid' : 'error');

            newTransactions.push({ 
                id: `sim-${index}-${Date.now()}`,
                date: isoDate || rawDate || "---", 
                description: rawDesc || "---", 
                rawDescription: rawDesc || "---", 
                amount: isNaN(amount) ? 0 : amount, 
                originalAmount: rawAmount, 
                cleanedDescription: rawDesc, // LITERAL
                contributionType: finalType, 
                sourceIndex: index, 
                isValid, 
                status 
            });
        });

        setProcessedTransactions(newTransactions);
    }, [gridData, activeMapping]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);

        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };

            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = updatedTx;
                return n;
            });

            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], updatedTx);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

import React, { useState } from 'react';
import { PlayCircleIcon, SparklesIcon, WrenchScrewdriverIcon } from '../../Icons';
import { inferMappingFromSample } from '../../../services/geminiService';
import { useUI } from '../../../contexts/UIContext';

interface MappingControlsProps {
    mapping: any;
    setMapping: (mapping: any) => void;
    columnCount: number;
    onSimulate: () => void;
    gridData: string[][];
}

export const MappingControls: React.FC<MappingControlsProps> = ({
    mapping,
    setMapping,
    columnCount,
    onSimulate,
    gridData
}) => {
    const [isAiLoading, setIsAiLoading] = useState(false);
    const { showToast } = useUI();

    if (!mapping) return null;

    const updateField = (field: string, value: string) => {
        const val = value === "" ? -1 : parseInt(value);
        setMapping({ ...mapping, [field]: val });
    };

    const handleAiSuggest = async () => {
        if (!gridData || gridData.length === 0) {
            showToast("Aguarde o carregamento dos dados.", "error");
            return;
        }

        setIsAiLoading(true);
        try {
            const sample = gridData.slice(0, 15).map(row => row.join(';')).join('\n');
            const suggestion = await inferMappingFromSample(sample);

            if (suggestion) {
                setMapping({
                    ...mapping,
                    dateColumnIndex: suggestion.dateColumnIndex ?? -1,
                    descriptionColumnIndex: suggestion.descriptionColumnIndex ?? -1,
                    amountColumnIndex: suggestion.amountColumnIndex ?? -1,
                    typeColumnIndex: suggestion.typeColumnIndex ?? -1,
                    skipRowsStart: suggestion.skipRowsStart ?? 0
                });
                showToast(`IA sugeriu mapeamento. Verifique se está correto.`, "success");
            }
        } catch (e: any) {
            showToast("Falha na sugestão da IA.", "error");
        } finally {
            setIsAiLoading(false);
        }
    };

    const ManualInput = ({ label, field, value, color }: { label: string, field: string, value: number, color: string }) => (
        <div className="flex flex-col gap-1">
            <label className={`text-[8px] font-black uppercase tracking-tighter ${color} ml-1`}>{label}</label>
            <div className="flex items-center gap-1 bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700 px-2 py-1 shadow-sm focus-within:ring-1 focus-within:ring-indigo-500">
                <span className="text-[9px] font-bold text-slate-400">Col.</span>
                <input 
                    type="number" 
                    min="-1"
                    max={columnCount > 0 ? columnCount - 1 : 20}
                    value={value === -1 ? "" : value} 
                    onChange={(e) => updateField(field, e.target.value)}
                    placeholder="N/A"
                    className="bg-transparent text-xs font-black outline-none w-8 text-slate-700 dark:text-white"
                />
            </div>
        </div>
    );

    return (
        <div className="flex flex-wrap gap-4 items-end flex-1">
            <div className="flex gap-2 p-2 bg-slate-100 dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700">
                <ManualInput label="Data" field="dateColumnIndex" value={mapping.dateColumnIndex} color="text-blue-500" />
                <ManualInput label="Descrição" field="descriptionColumnIndex" value={mapping.descriptionColumnIndex} color="text-purple-500" />
                <ManualInput label="Valor" field="amountColumnIndex" value={mapping.amountColumnIndex} color="text-emerald-500" />
                <div className="flex flex-col gap-1">
                    <label className="text-[8px] font-black uppercase tracking-tighter text-slate-400 ml-1">Pular Linhas</label>
                    <div className="flex items-center gap-1 bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700 px-2 py-1 shadow-sm">
                        <input 
                            type="number" 
                            min="0"
                            value={mapping.skipRowsStart || 0} 
                            onChange={(e) => setMapping({...mapping, skipRowsStart: parseInt(e.target.value) || 0})}
                            className="bg-transparent text-xs font-black outline-none w-8 text-slate-700 dark:text-white"
                        />
                    </div>
                </div>
            </div>

            <div className="flex gap-2">
                <button 
                    onClick={handleAiSuggest}
                    disabled={isAiLoading || gridData.length === 0}
                    className="flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-bold uppercase transition-all bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-500 hover:text-indigo-600 hover:border-indigo-200 shadow-sm disabled:opacity-50"
                >
                    {isAiLoading ? (
                        <svg className="animate-spin h-3.5 w-3.5" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    ) : (
                        <SparklesIcon className="w-3.5 h-3.5" />
                    )}
                    <span>{isAiLoading ? 'Lendo...' : 'Sugerir IA'}</span>
                </button>

                <button 
                    onClick={onSimulate}
                    disabled={gridData.length === 0}
                    className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[10px] font-bold uppercase shadow-lg shadow-indigo-500/20 transition-all active:scale-95 disabled:opacity-50"
                >
                    <PlayCircleIcon className="w-4 h-4" />
                    <span>Aplicar & Simular</span>
                </button>
            </div>
        </div>
    );
};

import React from 'react';
import { SparklesIcon, ExclamationTriangleIcon } from '../../Icons';

interface SpreadsheetRendererProps {
    data: string[][];
    isLoading?: boolean;
    detectedMapping?: any;
    isAiProcessed?: boolean;
    isImage?: boolean;
}

export const SpreadsheetRenderer: React.FC<SpreadsheetRendererProps> = ({ 
    data, 
    isLoading, 
    detectedMapping, 
    isAiProcessed,
    isImage = false
}) => {
    const getColumnLabel = (index: number) => {
        let label = '';
        let i = index;
        while (i >= 0) {
            label = String.fromCharCode((i % 26) + 65) + label;
            i = Math.floor(i / 26) - 1;
        }
        return `${label} (${index})`; // Mostra o índice numérico para facilitar o mapeamento
    };

    const getColumnHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-50 dark:bg-blue-900/30 border-x-2 border-blue-500/50';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-50 dark:bg-emerald-900/30 border-x-2 border-emerald-500/50';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-50 dark:bg-purple-900/30 border-x-2 border-purple-500/50';
        return '';
    };

    const getColumnHeaderHighlight = (index: number) => {
        if (!detectedMapping) return '';
        if (index === detectedMapping.dateColumnIndex) return 'bg-blue-500 text-white dark:bg-blue-600';
        if (index === detectedMapping.amountColumnIndex) return 'bg-emerald-500 text-white dark:bg-emerald-600';
        if (index === detectedMapping.descriptionColumnIndex) return 'bg-purple-500 text-white dark:bg-purple-600';
        return '';
    }

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 space-y-4 bg-slate-50 dark:bg-slate-900">
                <div className="animate-spin rounded-full h-10 w-10 border-4 border-indigo-500 border-t-transparent"></div>
                <p className="text-xs font-bold uppercase tracking-widest">Carregando visualização...</p>
            </div>
        );
    }

    if (!data || data.length === 0) {
        if (isImage) return null;
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center bg-slate-50 dark:bg-slate-900/50">
                <ExclamationTriangleIcon className="w-12 h-12 mb-3 opacity-20" />
                <p className="text-sm font-bold text-slate-500 dark:text-slate-300">Visualização indisponível</p>
            </div>
        );
    }

    const maxCols = data.reduce((max, row) => Math.max(max, row.length), 0);
    const colIndices = Array.from({ length: maxCols }, (_, i) => i);

    return (
        <div className="absolute inset-0 overflow-auto custom-scrollbar bg-[#f8f9fa] dark:bg-[#1e1e1e] select-text">
            <table className="border-collapse table-fixed min-w-full">
                <thead className="sticky top-0 z-20">
                    <tr>
                        <th className="w-10 min-w-[40px] bg-[#e6e6e6] dark:bg-[#333] border-r border-b border-[#c0c0c0] dark:border-[#555] sticky left-0 z-30"></th>
                        {colIndices.map(colIndex => (
                            <th key={colIndex} className={`bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[9px] font-black uppercase h-8 min-w-[120px] select-none transition-colors ${getColumnHeaderHighlight(colIndex) || 'text-slate-500'}`}>
                                {getColumnLabel(colIndex)}
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {data.slice(0, 300).map((row, rowIndex) => (
                        <tr key={rowIndex} className="h-7 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                            <td className="sticky left-0 z-10 bg-[#f0f0f0] dark:bg-[#2d2d2d] border-r border-b border-[#d4d4d4] dark:border-[#555] text-center text-[9px] font-bold text-slate-400 select-none w-10">
                                {rowIndex}
                            </td>
                            {colIndices.map(colIndex => (
                                <td 
                                    key={`${rowIndex}-${colIndex}`} 
                                    className={`border-r border-b border-[#e0e0e0] dark:border-[#444] px-2 py-1 text-[11px] text-slate-800 dark:text-slate-200 whitespace-nowrap overflow-hidden text-ellipsis cursor-cell ${getColumnHighlight(colIndex)}`}
                                >
                                    {row[colIndex]}
                                </td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (Especialista em Sicoob e layouts sem colunas)
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any[]> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `VOCÊ É UM ANALISTA BANCÁRIO ESPECIALISTA EM EXTRATOS DE BLOCO.
        Analise o texto abaixo. Ele contém transações onde a descrição pode estar em várias linhas e os valores estão à direita.

        TEXTO BRUTO:
        ${rawText.substring(0, 8000)}

        SUAS INSTRUÇÕES:
        1. Identifique cada transação completa. 
        2. Combine linhas de descrição que pertençam ao mesmo evento (Ex: "Recebimento Pix" + "Nome da Pessoa" + "CPF").
        3. Identifique o valor financeiro correspondente. Se tiver "C", é positivo. Se tiver "D" ou for saída, é negativo.
        4. Converta datas para YYYY-MM-DD.

        REGRAS PARA O JSON:
        - "date": Data em ISO
        - "description": Nome completo e limpo do favorecido/pagador
        - "amount": Número (float)
        - "type": Tipo curto (PIX, TED, DOC, etc)

        RETORNE APENAS UM JSON ARRAY: [{date, description, amount, type}]`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json"
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    });
};

export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `AJA COMO UM ARQUITETO DE DADOS. Analise este extrato.
