const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (Especialista em Sicoob e layouts sem colunas)
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any[]> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `VOCÊ É UM ANALISTA BANCÁRIO ESPECIALISTA EM EXTRATOS DE BLOCO.
        Analise o texto abaixo. Ele contém transações onde a descrição pode estar em várias linhas e os valores estão à direita.

        TEXTO BRUTO:
        ${rawText.substring(0, 8000)}

        SUAS INSTRUÇÕES:
        1. Identifique cada transação completa. 
        2. Combine linhas de descrição que pertençam ao mesmo evento (Ex: "Recebimento Pix" + "Nome da Pessoa" + "CPF").
        3. Identifique o valor financeiro correspondente. Se tiver "C", é positivo. Se tiver "D" ou for saída, é negativo.
        4. Converta datas para YYYY-MM-DD.

        REGRAS PARA O JSON:
        - "date": Data em ISO
        - "description": Nome completo e limpo do favorecido/pagador
        - "amount": Número (float)
        - "type": Tipo curto (PIX, TED, DOC, etc)

        RETORNE APENAS UM JSON ARRAY: [{date, description, amount, type}]`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json"
            }
        });

        return response.text ? JSON.parse(response.text) : [];
    });
};

