import { 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon, 
    InformationCircleIcon, 
    BoltIcon, 
    WhatsAppIcon, 
    EllipsisVerticalIcon, 
    PlusCircleIcon, 
    ArrowPathIcon, 
    EnvelopeIcon, 
    CheckCircleIcon, 
    DocumentDuplicateIcon, 
    ArrowsRightLeftIcon, 
    XMarkIcon 
} from '../components/Icons';
