const BankRow: React.FC<{ 
    bank: any, 
    isUploaded: boolean, 
    handleStatementUpload: any, 
    setIsGmailModalOpen: any, 
    removeBankStatementFile: any,
    triggerUpdate: () => void 
}> = ({ bank, isUploaded, handleStatementUpload, setIsGmailModalOpen, removeBankStatementFile, triggerUpdate }) => {

    // CONTEXT ACCESS FOR APPEND LOGIC
    const { fileModels, effectiveIgnoreKeywords, setBankStatementFile, activeBankFiles } = useContext(AppContext);
    const { user } = useAuth();
    const { showToast } = useUI();

    const [menuOpen, setMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);

    const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });

    const uploaderRef = useRef<FileUploaderHandle>(null);
    const menuRef = useRef<HTMLDivElement>(null);
    const buttonRef = useRef<HTMLButtonElement>(null);

    const triggerUpdateRef = useRef(triggerUpdate);
    useEffect(() => {
        triggerUpdateRef.current = triggerUpdate;
    }, [triggerUpdate]);

    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    const toggleMenu = () => {
        if (menuOpen) {
            setMenuOpen(false);
        } else if (buttonRef.current) {
            const rect = buttonRef.current.getBoundingClientRect();
            setMenuPosition({
                top: rect.bottom + window.scrollY + 5,
                left: rect.right - 224 + window.scrollX
            });
            setMenuOpen(true);
        }
    };

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (
                menuRef.current && !menuRef.current.contains(event.target as Node) &&
                buttonRef.current && !buttonRef.current.contains(event.target as Node)
            ) {
                setMenuOpen(false);
            }
        };
        const handleScroll = () => {
            if (menuOpen) setMenuOpen(false);
        };

        if (menuOpen) {
            document.addEventListener('mousedown', handleClickOutside);
            window.addEventListener('scroll', handleScroll, true);
        }
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
            window.removeEventListener('scroll', handleScroll, true);
        };
    }, [menuOpen]);

    const closeMenu = () => setMenuOpen(false);

    // LOGICA DE APPEND MANUAL (Commit-based)
    const handleAppend = async (content: string, fileName: string, rawFile: File) => {
        if (!user) return;
        setIsUploading(true);
        try {
            // Fix: Await processFileContent promise
            const result = await processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords);
            const newTransactions = result.transactions;

            if (newTransactions.length === 0) {
                showToast("Nenhuma transação válida encontrada.", "error");
                setIsUploading(false);
                return;
            }

            // PERSISTÊNCIA REAL COM DEDUPLICAÇÃO
            const launchResult = await LaunchService.launchToBank(user.id, bank.id, newTransactions);

            if (launchResult.added > 0) {
                // COMMIT VISUAL APÓS SUCESSO NO BANCO
                setBankStatementFile((prevFiles: any[]) => {
                    const existingIndex = prevFiles.findIndex((f: any) => f.bankId === bank.id);
                    if (existingIndex === -1) {
                        return [...prevFiles, { bankId: bank.id, content, fileName, rawFile, processedTransactions: newTransactions }];
                    }
                    const currentFile = prevFiles[existingIndex];
                    const mergedTransactions = [...(currentFile.processedTransactions || []), ...newTransactions];
                    const newFiles = [...prevFiles];
                    newFiles[existingIndex] = { ...currentFile, processedTransactions: mergedTransactions };
                    return newFiles;
                });
                showToast(`${launchResult.added} transações adicionadas!`, "success");
            } else if (launchResult.skipped > 0) {
                showToast("Registros duplicados ignorados.", "warning");
            }

            setTimeout(() => triggerUpdateRef.current(), 800);

        } catch (e: any) {
            showToast("Erro ao adicionar: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File) => {
        if (uploadModeRef.current === 'replace') {
            setIsUploading(true);
            await handleStatementUpload(content, fileName, bank.id, rawFile);
            setTimeout(() => {
                triggerUpdateRef.current();
                setIsUploading(false);
            }, 1000);
        } else {
            await handleAppend(content, fileName, rawFile);
        }
        closeMenu();
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        closeMenu();
    };

    return (
        <div className={`p-3 rounded-2xl border transition-all duration-200 flex items-center justify-between gap-3 relative group ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>
            <div className="hidden">
                <FileUploader 
                    ref={uploaderRef}
                    id={`update-bank-${bank.id}`}
                    title="Upload Hidden"
                    onFileUpload={handleFileUploadWrapper}
                    isUploaded={false}
                    uploadedFileName={null}
                    onParsingStatusChange={setIsUploading}
                />
            </div>

            <div className="flex flex-col min-w-0">
                <span className="font-bold text-xs text-slate-800 dark:text-slate-200 truncate">{bank.name}</span>
                {isUploaded ? (
                    <span className="flex items-center gap-1 text-[10px] text-emerald-600 dark:text-emerald-400 font-medium">
                        <CheckCircleIcon className="w-3 h-3" /> Lista Viva Ativa
                    </span>
                ) : (
                    <span className="text-[10px] text-slate-400 italic">Nenhum extrato vinculado</span>
                )}
            </div>

            <div className="relative">
                {isUploading ? (
                    <div className="p-2">
                        <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    </div>
                ) : (
                    <button 
                        ref={buttonRef}
                        onClick={toggleMenu}
                        className={`p-2 rounded-full transition-all duration-200 border relative z-10 ${menuOpen ? 'bg-blue-50 text-brand-blue border-blue-200' : 'bg-white dark:bg-slate-800 text-slate-400 hover:text-brand-blue border-slate-200 hover:shadow-sm'}`}
                        title="Opções do Extrato"
                    >
                        {isUploaded ? <EllipsisVerticalIcon className="w-5 h-5 stroke-[1.5]" /> : <CloudArrowUpIcon className="w-5 h-5 stroke-[1.5]" />}
                    </button>
                )}

                {menuOpen && createPortal(
                    <div ref={menuRef} style={{ position: 'fixed', top: menuPosition.top, left: menuPosition.left, zIndex: 9999 }} className="w-56 bg-white dark:bg-slate-800 rounded-xl shadow-2xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-scale-in">
                        <div className="flex flex-col py-1">
                            <button onClick={() => triggerUpload('append')} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 w-full text-left transition-colors">
                                <div className="p-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-500"><PlusCircleIcon className="w-3.5 h-3.5" /></div>
                                <div><span className="block">Adicionar arquivo</span><span className="text-[9px] font-normal text-slate-400">Somar à lista atual</span></div>
                            </button>
                            <button onClick={() => triggerUpload('replace')} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 w-full text-left transition-colors">
                                <div className="p-1.5 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500"><ArrowPathIcon className="w-3.5 h-3.5" /></div>
                                <div><span className="block">Substituir tudo</span><span className="text-[9px] font-normal text-slate-400">Trocar lista atual</span></div>
                            </button>
                            <button onClick={() => { setIsGmailModalOpen(true); closeMenu(); }} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 w-full text-left transition-colors">
                                <div className="p-1.5 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-500"><EnvelopeIcon className="w-3.5 h-3.5" /></div>
                                <div><span className="block">Importar Gmail</span><span className="text-[9px] font-normal text-slate-400">Buscar comprovantes</span></div>
                            </button>
                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>
                            <button onClick={() => { if(isUploaded) removeBankStatementFile(bank.id); closeMenu(); }} disabled={!isUploaded} className={`flex items-center gap-3 px-4 py-2.5 text-xs font-bold w-full text-left ${!isUploaded ? 'opacity-50 text-slate-400' : 'text-red-500 hover:bg-red-50'}`}>
                                <div className={`p-1.5 rounded-lg ${!isUploaded ? 'bg-slate-100' : 'bg-red-50 text-red-500'}`}><TrashIcon className="w-3.5 h-3.5" /></div>
                                <span>Remover extrato</span>
                            </button>
                        </div>
                    </div>, document.body
                )}
            </div>
        </div>
    );
};

