import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;

        // Normalização especial para texto extraído de PDF (múltiplos espaços -> delimitador)
        const isLikelyPdf = filename.toLowerCase().endsWith('.pdf') || content.includes('    ');
        let normalizedContent = content;
        if (isLikelyPdf && !content.includes(';')) {
            normalizedContent = content.replace(/\s{2,}/g, ';');
        }

        const fileFp = Fingerprinter.generate(normalizedContent);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, filename = '') => {
        if (!models || models.length === 0) return [];

        // Mesma normalização do canHandle para garantir o match do objeto
        const isLikelyPdf = String(filename).toLowerCase().endsWith('.pdf') || content.includes('    ');
        let normalizedContent = content;
        if (isLikelyPdf && !content.includes(';')) {
            normalizedContent = content.replace(/\s{2,}/g, ';');
        }

        const fileFp = Fingerprinter.generate(normalizedContent);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) return [];

        // MODO BLOCK: IA CONTEXTUAL (Obrigatório para PDFs complexos)
        if ((matchingModel.mapping as any).extractionMode === 'BLOCK' || isLikelyPdf) {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description,
                contributionType: t.type || 'AUTO'
            }));
        }

        // MODO COLUMNS: TRADICIONAL
        const transactions: Transaction[] = [];
        const lines = normalizedContent.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter || ';';

        lines.slice(skipRowsStart || 0).forEach((line, index) => {
            const cols = line.split(delimiter);
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawAmount = (cols[amountColumnIndex] || '').trim();
            const cleanVal = rawAmount.replace(/[R$\s]/g, '').replace(',', '.');
            const numericValue = parseFloat(cleanVal) * (rawAmount.includes('-') || rawAmount.toUpperCase().endsWith('D') ? -1 : 1);

            if (!isNaN(numericValue)) {
                transactions.push({
                    id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                    date: DateResolver.resolveToISO((cols[dateColumnIndex] || '').trim(), yearAnchor) || (cols[dateColumnIndex] || '').trim(),
                    description: (cols[descriptionColumnIndex] || '').trim(),
                    rawDescription: (cols[descriptionColumnIndex] || '').trim(),
                    amount: numericValue,
                    originalAmount: rawAmount,
                    cleanedDescription: (cols[descriptionColumnIndex] || '').trim(),
                    contributionType: typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex as number] || '').trim() : 'AUTO'
                });
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        // Normalização de PDF para o parser genérico também
        const normalized = content.includes('    ') ? content.replace(/\s{2,}/g, ';') : content;
        const lines = normalized.split(/\r?\n/).filter(l => l.trim().length > 0);

        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);
        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);
            if (!date || isNaN(amount) || amount === 0) return null;
            return {
                id: `gen-${i}-${Date.now()}`, date, amount,
                description: row[nIdx] || 'S/D', rawDescription: row[nIdx] || 'S/D',
                originalAmount: row[aIdx], cleanedDescription: NameResolver.clean(row[nIdx], globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(row[nIdx])
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        if (overrideModel) {
            const result = await (DatabaseModelStrategy.parse as any)(content, yearAnchor, [overrideModel], [], filename);
            return { transactions: result as Transaction[], strategyName: overrideModel.name };
        }

        if (DatabaseModelStrategy.canHandle(filename, content, models)) {
            const result = await (DatabaseModelStrategy.parse as any)(content, yearAnchor, models, [], filename);
            const transactions = result as Transaction[];
            if (transactions.length > 0) return { transactions, strategyName: 'Modelo Aprendido' };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';
import { NameResolver } from '../processors/NameResolver';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V3 - DIGITAL CORE)
 * --------------------------------------------------------------------------
 * Único ponto de entrada para dados brutos.
 */

export interface IngestionResult {
    source: 'upload' | 'gmail';
    transactions: Transaction[];
    strategyUsed: string;
    fingerprint: any;
    appliedModelId?: string;
}

export const IngestionOrchestrator = {
    /**
     * Porta 1: Processamento de Arquivos Físicos (PDF, CSV, Excel, TXT)
     */
    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        // Normalização de conteúdo para arquivos PDF (converter espaços em delimitadores virtuais)
        let processedContent = content;
        if (file.name.toLowerCase().endsWith('.pdf') && !content.includes(';')) {
            processedContent = content.replace(/\s{2,}/g, ';');
        }

        const fingerprint = Fingerprinter.generate(processedContent);

        // Aguardar a execução assíncrona do motor de estratégias
        const result = await StrategyEngine.process(file.name, content, models, globalKeywords);

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint || { columnCount: 0 }
        };
    },

    /**
     * Porta 2: Processamento de Dados Virtuais (Gmail / API Sync)
     */
    async processVirtualData(
        sourceName: string,
        data: any[],
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        const yearAnchor = new Date().getFullYear();

        const transactions: Transaction[] = data.map((item, index) => {
            const rawDesc = item.description || item.memo || 'Sem descrição';
            const rawAmount = String(item.amount);

            const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
            const isoDate = DateResolver.resolveToISO(item.date, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);

            return {
                id: `gmail-sync-${Date.now()}-${index}`,
                date: isoDate,
                description: rawDesc.trim(),
                rawDescription: `GMAIL_ORIGIN: ${rawDesc.trim()}`,
                amount: parseFloat(amountStr),
                originalAmount: rawAmount,
                cleanedDescription: cleanedDesc,
                contributionType: item.type || 'PIX'
            };
        }).filter(t => t.date && !isNaN(t.amount));

        const virtualContent = transactions.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        const fingerprint = Fingerprinter.generate(virtualContent) || { source: 'gmail_api' };

        return {
            source: 'gmail',
            transactions,
            strategyUsed: 'GATEWAY_IA_GMAIL',
            fingerprint: { ...fingerprint, is_virtual: true }
        };
    }
};

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;

        // Normalização especial para texto extraído de PDF (múltiplos espaços -> delimitador)
        const isLikelyPdf = filename.toLowerCase().endsWith('.pdf') || content.includes('    ');
        let normalizedContent = content;
        if (isLikelyPdf && !content.includes(';')) {
            normalizedContent = content.replace(/\s{2,}/g, ';');
        }

        const fileFp = Fingerprinter.generate(normalizedContent);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];

        // Fix: Use globalKeywords or filename from closure/context if available
        // In the current architecture, parse signature expects string[] for keywords.
        const isLikelyPdf = content.includes('    ');
        let normalizedContent = content;
        if (isLikelyPdf && !content.includes(';')) {
            normalizedContent = content.replace(/\s{2,}/g, ';');
        }

        const fileFp = Fingerprinter.generate(normalizedContent);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) return [];

        // MODO BLOCK: IA CONTEXTUAL (Obrigatório para PDFs complexos)
        if ((matchingModel.mapping as any).extractionMode === 'BLOCK' || isLikelyPdf) {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description,
                contributionType: t.type || 'AUTO'
            }));
        }

        // MODO COLUMNS: TRADICIONAL
        const transactions: Transaction[] = [];
        const lines = normalizedContent.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter || ';';

        lines.slice(skipRowsStart || 0).forEach((line, index) => {
            const cols = line.split(delimiter);
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawAmount = (cols[amountColumnIndex] || '').trim();
            const cleanVal = rawAmount.replace(/[R$\s]/g, '').replace(',', '.');
            const numericValue = parseFloat(cleanVal) * (rawAmount.includes('-') || rawAmount.toUpperCase().endsWith('D') ? -1 : 1);

            if (!isNaN(numericValue)) {
                transactions.push({
                    id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                    date: DateResolver.resolveToISO((cols[dateColumnIndex] || '').trim(), yearAnchor) || (cols[dateColumnIndex] || '').trim(),
                    description: (cols[descriptionColumnIndex] || '').trim(),
                    rawDescription: (cols[descriptionColumnIndex] || '').trim(),
                    amount: numericValue,
                    originalAmount: rawAmount,
                    cleanedDescription: (cols[descriptionColumnIndex] || '').trim(),
                    contributionType: typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex as number] || '').trim() : 'AUTO'
                });
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        // Normalização de PDF para o parser genérico também
        const normalized = content.includes('    ') ? content.replace(/\s{2,}/g, ';') : content;
        const lines = normalized.split(/\r?\n/).filter(l => l.trim().length > 0);

        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);
        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);
            if (!date || isNaN(amount) || amount === 0) return null;
            return {
                id: `gen-${i}-${Date.now()}`, date, amount,
                description: row[nIdx] || 'S/D', rawDescription: row[nIdx] || 'S/D',
                originalAmount: row[aIdx], cleanedDescription: NameResolver.clean(row[nIdx], globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(row[nIdx])
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        if (overrideModel) {
            // Fix: Call parse with correct parameters to match signature
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], globalKeywords);
            return { transactions: result as Transaction[], strategyName: overrideModel.name };
        }

        if (DatabaseModelStrategy.canHandle(filename, content, models)) {
            // Fix: Call parse with correct parameters to match signature
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, models, []);
            const transactions = result as Transaction[];
            if (transactions.length > 0) return { transactions, strategyName: 'Modelo Aprendido' };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';
import { NameResolver } from '../processors/NameResolver';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V3 - DIGITAL CORE)
 * --------------------------------------------------------------------------
 * Único ponto de entrada para dados brutos.
 */

export interface IngestionResult {
    source: 'upload' | 'gmail';
    transactions: Transaction[];
    strategyUsed: string;
    fingerprint: any;
    appliedModelId?: string;
}

export const IngestionOrchestrator = {
    /**
     * Porta 1: Processamento de Arquivos Físicos (PDF, CSV, Excel, TXT)
     */
    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        // 1. NORMALIZAÇÃO ESTRUTURAL DE PDF (CRÍTICO)
        // PDFs extraídos como texto perdem os delimitadores. 
        // Convertemos sequências de espaços em ';' para simular colunas e bater com o Fingerprint do Modelo.
        let processedContent = content;
        const isPdf = file.name.toLowerCase().endsWith('.pdf');

        if (isPdf && !content.includes(';') && !content.includes('\t')) {
            processedContent = content
                .split(/\r?\n/)
                .map(line => line.trim().replace(/\s{2,}/g, ';'))
                .filter(line => line.length > 0)
                .join('\n');
        }

        const fingerprint = Fingerprinter.generate(processedContent);

        // 2. ROTEAMENTO DE ESTRATÉGIA
        // Passamos o conteúdo já normalizado para que o DatabaseModelStrategy consiga dar match
        const result = await StrategyEngine.process(file.name, processedContent, models, globalKeywords);

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint || { columnCount: 0 }
        };
    },

    /**
     * Porta 2: Processamento de Dados Virtuais (Gmail / API Sync)
     */
    async processVirtualData(
        sourceName: string,
        data: any[],
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        const yearAnchor = new Date().getFullYear();

        const transactions: Transaction[] = data.map((item, index) => {
            const rawDesc = item.description || item.memo || 'Sem descrição';
            const rawAmount = String(item.amount);

            const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
            const isoDate = DateResolver.resolveToISO(item.date, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);

            return {
                id: `gmail-sync-${Date.now()}-${index}`,
                date: isoDate,
                description: rawDesc.trim(),
                rawDescription: `GMAIL_ORIGIN: ${rawDesc.trim()}`,
                amount: parseFloat(amountStr),
                originalAmount: rawAmount,
                cleanedDescription: cleanedDesc,
                contributionType: item.type || 'PIX'
            };
        }).filter(t => t.date && !isNaN(t.amount));

        const virtualContent = transactions.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        const fingerprint = Fingerprinter.generate(virtualContent) || { source: 'gmail_api' };

        return {
            source: 'gmail',
            transactions,
            strategyUsed: 'GATEWAY_IA_GMAIL',
            fingerprint: { ...fingerprint, is_virtual: true }
        };
    }
};

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;

        // O conteúdo já vem normalizado do IngestionOrchestrator
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];

        const fileFp = Fingerprinter.generate(content);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) return [];

        // MODO BLOCK: IA CONTEXTUAL (Obrigatório para PDFs complexos ou marcados como BLOCK)
        // Se for PDF e não bateu colunas perfeitamente, usamos IA como salvaguarda
        const isLikelyPdf = content.includes(';'); 
        const extractionMode = (matchingModel.mapping as any).extractionMode;

        if (extractionMode === 'BLOCK' || (isLikelyPdf && extractionMode !== 'COLUMNS')) {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description,
                contributionType: t.type || 'AUTO'
            }));
        }

        // MODO COLUMNS: TRADICIONAL
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter || ';';

        lines.slice(skipRowsStart || 0).forEach((line, index) => {
            const cols = line.split(delimiter);
            if (cols.length <= Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) return;

            const rawAmount = (cols[amountColumnIndex] || '').trim();
            const cleanVal = rawAmount.replace(/[R$\s]/g, '').replace(',', '.');
            const numericValue = parseFloat(cleanVal) * (rawAmount.includes('-') || rawAmount.toUpperCase().endsWith('D') ? -1 : 1);

            if (!isNaN(numericValue)) {
                transactions.push({
                    id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                    date: DateResolver.resolveToISO((cols[dateColumnIndex] || '').trim(), yearAnchor) || (cols[dateColumnIndex] || '').trim(),
                    description: (cols[descriptionColumnIndex] || '').trim(),
                    rawDescription: (cols[descriptionColumnIndex] || '').trim(),
                    amount: numericValue,
                    originalAmount: rawAmount,
                    cleanedDescription: (cols[descriptionColumnIndex] || '').trim(),
                    contributionType: typeColumnIndex !== undefined && typeColumnIndex !== -1 ? (cols[typeColumnIndex as number] || '').trim() : 'AUTO'
                });
            }
        });
        return transactions;
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));
        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);
            if (!date || isNaN(amount) || amount === 0) return null;
            return {
                id: `gen-${i}-${Date.now()}`, date, amount,
                description: row[nIdx] || 'S/D', rawDescription: row[nIdx] || 'S/D',
                originalAmount: row[aIdx], cleanedDescription: NameResolver.clean(row[nIdx], globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(row[nIdx])
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        // Prioridade 1: Modelo forçado pelo reconhecimento prévio
        if (overrideModel) {
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, [overrideModel], globalKeywords);
            return { transactions: result as Transaction[], strategyName: overrideModel.name };
        }

        // Prioridade 2: Match automático de modelo
        if (DatabaseModelStrategy.canHandle(filename, content, models)) {
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, models, []);
            const transactions = result as Transaction[];
            if (transactions.length > 0) return { transactions, strategyName: 'Modelo Aprendido' };
        }

        // Fallback: Parser Genérico
        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import React, { useContext, useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { AppContext } from '../contexts/AppContext';
import { useTranslation } from '../contexts/I18nContext';
import { useAuth } from '../contexts/AuthContext';
import { useUI } from '../contexts/UIContext';
import { FileUploader, FileUploaderHandle } from '../components/FileUploader';
import { 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon, 
    InformationCircleIcon, 
    BoltIcon, 
    WhatsAppIcon, 
    EllipsisVerticalIcon, 
    PlusCircleIcon, 
    ArrowPathIcon, 
    EnvelopeIcon, 
    CheckCircleIcon, 
    DocumentDuplicateIcon, 
    ArrowsRightLeftIcon, 
    XMarkIcon 
} from '../components/Icons';
import { GmailModal } from '../features/gmail/GmailModal';
import { InitialComparisonModal } from '../components/modals/InitialComparisonModal';
import { processFileContent } from '../services/processingService';
import { LaunchService } from '../services/LaunchService';

// --- SMART BANK CARD COMPONENT ---
const SmartBankCard: React.FC<{ bank: any }> = ({ bank }) => {
    const { 
        activeBankFiles,
        selectedBankIds,
        toggleBankSelection,
        handleStatementUpload, 
        removeBankStatementFile,
        fileModels,
        effectiveIgnoreKeywords,
        setBankStatementFile
    } = useContext(AppContext);

    const { user } = useAuth();
    const { showToast } = useUI();
    const { t } = useTranslation();

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);

    const [menuPos, setMenuPos] = useState<{x: number, y: number} | null>(null);
    const [isDragging, setIsDragging] = useState(false);
    const dragStartRef = useRef<{x: number, y: number}>({ x: 0, y: 0 });

    const uploaderRef = useRef<FileUploaderHandle>(null);
    const menuRef = useRef<HTMLDivElement>(null);
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    const bankFiles = activeBankFiles.filter(f => f.bankId === bank.id);
    const isUploaded = bankFiles.length > 0;
    const isSelected = selectedBankIds.includes(bank.id);
    const totalTransactions = bankFiles.reduce((acc, f) => acc + (f.processedTransactions?.length || 0), 0);

    const toggleMenu = () => {
        setIsMenuOpen(!isMenuOpen);
        setMenuPos(null);
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (menuRef.current) {
            setIsDragging(true);
            const rect = menuRef.current.getBoundingClientRect();
            dragStartRef.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
        }
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isDragging) {
                setMenuPos({ x: e.clientX - dragStartRef.current.x, y: e.clientY - dragStartRef.current.y });
            }
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging]);

    const handleAppend = async (content: string, fileName: string, rawFile: File) => {
        if (!user) return;
        setIsUploading(true);
        try {
            const result = await processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords);
            const newTransactions = result.transactions;

            if (newTransactions.length === 0) {
                showToast("Nenhuma transação encontrada no arquivo.", "error");
                setIsUploading(false);
                return;
            }

            const launchResult = await LaunchService.launchToBank(user.id, bank.id, newTransactions);

            if (launchResult.added > 0) {
                setBankStatementFile((prevFiles: any[]) => [
                    ...prevFiles, 
                    { bankId: bank.id, content, fileName, rawFile, processedTransactions: newTransactions }
                ]);
                showToast(`${launchResult.added} transações adicionadas!`, "success");
            } else {
                showToast("Nenhum dado novo encontrado.", "warning");
            }
        } catch (e: any) {
            showToast("Erro ao adicionar: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File) => {
        setIsUploading(true);
        try {
            if (uploadModeRef.current === 'replace') {
                await handleStatementUpload(content, fileName, bank.id, rawFile);
            } else {
                await handleAppend(content, fileName, rawFile);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsUploading(false);
            setIsMenuOpen(false);
        }
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        setIsMenuOpen(false);
    };

    const removeSpecificFile = async (fileToRemove: any) => {
        if (!user) return;
        setIsUploading(true);
        setIsMenuOpen(false);

        try {
            const remainingFiles = bankFiles.filter(f => f !== fileToRemove);
            await LaunchService.clearBankLaunch(user.id, bank.id);

            if (remainingFiles.length > 0) {
                const allTxs = remainingFiles.flatMap(f => f.processedTransactions || []);
                if (allTxs.length > 0) {
                    await LaunchService.launchToBank(user.id, bank.id, allTxs);
                }
            }

            setBankStatementFile((prev: any[]) => prev.filter(f => f !== fileToRemove));
            showToast("Arquivo removido.", "success");
        } catch (e: any) {
            showToast("Erro ao remover arquivo.", "error");
        } finally {
            setIsUploading(false);
        }
    };

    return (
        <div className={`p-4 rounded-2xl border transition-all duration-300 flex items-center justify-between gap-3 group relative ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/50 border-slate-100 dark:border-slate-700 hover:border-blue-200 dark:hover:border-blue-800'}`}>
            <div className="hidden">
                <FileUploader 
                    ref={uploaderRef}
                    id={`bank-${bank.id}`}
                    title="Upload"
                    onFileUpload={handleFileUploadWrapper}
                    isUploaded={false}
                    uploadedFileName={null}
                    onParsingStatusChange={setIsUploading}
                />
            </div>

            {isUploaded && (
                <div 
                    onClick={() => toggleBankSelection(bank.id)}
                    className={`w-5 h-5 rounded-md border flex items-center justify-center cursor-pointer transition-all ${isSelected ? 'bg-emerald-500 border-emerald-500' : 'bg-white border-emerald-200 hover:border-emerald-400'}`}
                >
                    {isSelected && <CheckCircleIcon className="w-3.5 h-3.5 text-white" />}
                </div>
            )}

            <div className="flex flex-col min-w-0 flex-1">
                <span className={`font-bold text-sm truncate ${isSelected ? 'text-emerald-700 dark:text-emerald-300' : 'text-slate-800 dark:text-slate-200'}`}>{bank.name}</span>
                {isUploaded ? (
                    <div className="flex items-center gap-2 mt-0.5">
                        <span className="text-[10px] text-emerald-600 dark:text-emerald-400 font-bold uppercase tracking-wide">Lista Viva</span>
                        <span className="text-[9px] text-slate-400">({totalTransactions} txs)</span>
                    </div>
                ) : <span className="text-[10px] text-slate-400 italic mt-0.5">Nenhum arquivo</span>}
            </div>

            <div className="flex items-center gap-2">
                {isUploading ? (
                    <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : !isUploaded ? (
                    <button onClick={() => triggerUpload('replace')} className="px-4 py-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600 hover:border-brand-blue hover:text-brand-blue rounded-lg text-xs font-bold uppercase tracking-wide shadow-sm transition-all">{t('upload.statementButton')}</button>
                ) : (
                    <button onClick={toggleMenu} className={`p-2 rounded-full transition-all border ${isMenuOpen ? 'bg-blue-50 border-blue-200 text-brand-blue' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}><EllipsisVerticalIcon className="w-5 h-5" /></button>
                )}

                {isMenuOpen && createPortal(
                    <div ref={menuRef} style={{ position: 'fixed', left: menuPos ? menuPos.x : '50%', top: menuPos ? menuPos.y : '50%', transform: menuPos ? 'none' : 'translate(-50%, -50%)', zIndex: 9999, width: '280px' }} className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-scale-in">
                        <div onMouseDown={handleMouseDown} className="bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700 px-4 py-2 flex items-center justify-between cursor-move select-none">
                            <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400"><ArrowsRightLeftIcon className="w-3 h-3 rotate-45" /><span className="text-[10px] font-bold uppercase tracking-wider">Gerenciar Extratos</span></div>
                            <button onClick={() => setIsMenuOpen(false)} className="text-slate-400 hover:text-slate-600"><XMarkIcon className="w-4 h-4" /></button>
                        </div>
                        <div className="flex flex-col py-1">
                            <button onClick={() => triggerUpload('append')} className="flex items-center gap-3 px-4 py-3 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors">
                                <div className="p-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-500"><PlusCircleIcon className="w-4 h-4" /></div>
                                <div><span className="block">Adicionar arquivo</span><span className="text-[9px] font-normal text-slate-400">Somar à lista atual</span></div>
                            </button>
                            <button onClick={() => triggerUpload('replace')} className="flex items-center gap-3 px-4 py-3 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors">
                                <div className="p-1.5 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500"><ArrowPathIcon className="w-4 h-4" /></div>
                                <div><span className="block">Substituir tudo</span><span className="text-[9px] font-normal text-slate-400">Começar do zero</span></div>
                            </button>
                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>
                            <div className="px-4 py-1.5 text-[9px] font-bold text-slate-400 uppercase tracking-wider">Arquivos Ativos ({bankFiles.length}):</div>
                            <div className="max-h-32 overflow-y-auto custom-scrollbar">
                                {bankFiles.map((file, idx) => (
                                    <div key={`${idx}-${file.fileName}`} className="flex items-center justify-between px-4 py-2 hover:bg-slate-50 dark:hover:bg-slate-700/30 group/file">
                                        <div className="flex items-center gap-2 min-w-0"><DocumentDuplicateIcon className="w-3 h-3 text-slate-400 shrink-0" /><span className="text-[10px] text-slate-600 dark:text-slate-300 truncate max-w-[140px]">{file.fileName}</span></div>
                                        <button onClick={() => removeSpecificFile(file)} className="p-1 text-slate-400 hover:text-red-500 opacity-0 group-hover/file:opacity-100"><TrashIcon className="w-3 h-3" /></button>
                                    </div>
                                ))}
                            </div>
                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>
                            <button onClick={() => { removeBankStatementFile(bank.id); setIsMenuOpen(false); }} className="flex items-center gap-3 px-4 py-3 text-xs font-bold w-full text-left text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20">
                                <div className="p-1.5 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-500"><TrashIcon className="w-3.5 h-3.5" /></div>
                                <span>Excluir Tudo</span>
                            </button>
                        </div>
                    </div>, document.body
                )}
            </div>
        </div>
    );
};

